 &lt;h1 id=&#34;15-vs-code-详解&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#15-vs-code-详解&#34;&gt;#&lt;/a&gt; 15 vs code 详解&lt;/h1&gt;
&lt;h2 id=&#34;预定义变量&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#预定义变量&#34;&gt;#&lt;/a&gt; 预定义变量&lt;/h2&gt;
&lt;p&gt;支持下面的预定义变量:&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;&lt;strong&gt;${workspaceFolder}&lt;/strong&gt; - 当前工作目录 (根目录)&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;${workspaceFolderBasename}&lt;/strong&gt; - 当前文件的父目录&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;${file}&lt;/strong&gt; - 当前打开的文件名 (完整路径)&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;${relativeFile}&lt;/strong&gt; - 当前根目录到当前打开文件的相对路径 (包括文件名)&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;${relativeFileDirname}&lt;/strong&gt; - 当前根目录到当前打开文件的相对路径 (不包括文件名)&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;${fileBasename}&lt;/strong&gt; - 当前打开的文件名 (包括扩展名)&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;${fileBasenameNoExtension}&lt;/strong&gt; - 当前打开的文件名 (不包括扩展名)&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;${fileDirname}&lt;/strong&gt; - 当前打开文件的目录&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;${fileExtname}&lt;/strong&gt; - 当前打开文件的扩展名&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;${cwd}&lt;/strong&gt; - 启动时 task 工作的目录&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;${lineNumber}&lt;/strong&gt; - 当前激活文件所选行&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;${selectedText}&lt;/strong&gt; - 当前激活文件中所选择的文本&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;${execPath}&lt;/strong&gt; - vscode 执行文件所在的目录&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;${defaultBuildTask}&lt;/strong&gt; - 默认编译任务 (build task) 的名字&lt;/li&gt;
&lt;/ul&gt;
&lt;h2 id=&#34;预定义变量示例&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#预定义变量示例&#34;&gt;#&lt;/a&gt; 预定义变量示例:&lt;/h2&gt;
&lt;p&gt;假设你满足以下的条件&lt;/p&gt;
&lt;ol&gt;
&lt;li&gt;一个文件  &lt;code&gt;/home/your-username/your-project/folder/file.ext&lt;/code&gt;  在你的编辑器中打开；&lt;/li&gt;
&lt;li&gt;一个目录  &lt;code&gt;/home/your-username/your-project&lt;/code&gt;  作为你的根目录.&lt;/li&gt;
&lt;/ol&gt;
&lt;p&gt;下面的预定义变量则代表:&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;&lt;strong&gt;${workspaceFolder}&lt;/strong&gt; -  &lt;code&gt;/home/your-username/your-project&lt;/code&gt;&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;${workspaceFolderBasename}&lt;/strong&gt; -  &lt;code&gt;your-project&lt;/code&gt;&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;${file}&lt;/strong&gt; -  &lt;code&gt;/home/your-username/your-project/folder/file.ext&lt;/code&gt;&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;${relativeFile}&lt;/strong&gt; -  &lt;code&gt;folder/file.ext&lt;/code&gt;&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;${relativeFileDirname}&lt;/strong&gt; -  &lt;code&gt;folder&lt;/code&gt;&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;${fileBasename}&lt;/strong&gt; -  &lt;code&gt;file.ext&lt;/code&gt;&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;${fileBasenameNoExtension}&lt;/strong&gt; -  &lt;code&gt;file&lt;/code&gt;&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;${fileDirname}&lt;/strong&gt; -  &lt;code&gt;/home/your-username/your-project/folder&lt;/code&gt;&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;${fileExtname}&lt;/strong&gt; -  &lt;code&gt;.ext&lt;/code&gt;&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;${lineNumber}&lt;/strong&gt; - 光标所在行&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;${selectedText}&lt;/strong&gt; - 编辑器中所选择的文本&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;${execPath}&lt;/strong&gt; - Code.exe 的位&lt;/li&gt;
&lt;/ul&gt;
&lt;script type=&#34;text&amp;#x2F;javascript&#34; src=&#34;https://cdn.jsdelivr.net/npm/kity@2.0.4/dist/kity.min.js&#34;&gt;&lt;/script&gt;&lt;script type=&#34;text&amp;#x2F;javascript&#34; src=&#34;https://cdn.jsdelivr.net/npm/kityminder-core@1.4.50/dist/kityminder.core.min.js&#34;&gt;&lt;/script&gt;&lt;script defer=&#34;true&#34; type=&#34;text&amp;#x2F;javascript&#34; src=&#34;https://cdn.jsdelivr.net/npm/hexo-simple-mindmap@0.7.0/dist/mindmap.min.js&#34;&gt;&lt;/script&gt;&lt;link rel=&#34;stylesheet&#34; type=&#34;text&amp;#x2F;css&#34; href=&#34;https://cdn.jsdelivr.net/npm/hexo-simple-mindmap@0.7.0/dist/mindmap.min.css&#34;&gt;

 &lt;table&gt;
&lt;thead&gt;
&lt;tr&gt;
&lt;th style=&#34;text-align:center&#34;&gt;功能&lt;/th&gt;
&lt;th style=&#34;text-align:center&#34;&gt;快捷键&lt;/th&gt;
&lt;/tr&gt;
&lt;/thead&gt;
&lt;tbody&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;单行注释&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;[ctrl+k,ctrl+c] 或 ctrl+/&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;取消单行注释&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;[ctrl+k,ctrl+u] (按下 ctrl 不放，再按 k + u)&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;多行注释&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;[alt+shift+A]&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;多行注释&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;/**/&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;动行&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;alt+up/down&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;示&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;隐藏左侧目录栏 ctrl + b&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;制当前行&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;shift + alt +up/down&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;除当前行&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;shift + ctrl + k&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;制台终端显示与隐藏&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;ctrl + ~&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;找文件&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;安装 vs code 插件地址：ctrl + p&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;码格式化&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;shift + alt +f&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;建一个窗口&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;ctrl + shift + n&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;行增加缩进&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;ctrl + [&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;行减少缩进&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;ctrl + ]&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;裁剪尾随空格&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;去掉一行的末尾那些没用的空格) : ctrl + shift + x&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;字体放大&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;缩小: ctrl + (+ 或 -)&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;拆分编辑器&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;ctrl + 1/2/3&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;切换窗口&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;ctrl + shift + left/right&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;关闭编辑器窗口&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;ctrl + w&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;关闭所有窗口&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;ctrl + k + w&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;切换全屏&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;F11&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;自动换行&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;alt + z&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;显示&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;it: ctrl + shift + g&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;全局查找文件&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;ctrl + p&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;显示相关插件的命令&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;如：git log)：ctrl + shift + p&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;选中文字&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;shift + left / right / up / down&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;折叠代码&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;ctrl + k + 0-9 (0 是完全折叠)&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;展开代码&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;ctrl + k + j (完全展开代码)&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;删除行&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;ctrl + shift + k&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;快速切换主题&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;ctrl + k / ctrl + t&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;快速回到顶部&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;ctrl + home&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;快速回到底部&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;ctrl + end&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;格式化选定代码&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;ctrl + k / ctrl +f&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;选中代码&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;shift + 鼠标左键&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;多行同时添加内容&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;光标） ：ctrl + alt + up/down&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;全局替换&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;ctrl + shift + h&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;当前文件替换&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;ctrl + h&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;打开最近打开的文件&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;ctrl + r&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;打开新的命令窗&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;ctrl + shift + c&lt;/td&gt;
&lt;/tr&gt;
&lt;/tbody&gt;
&lt;/table&gt;
&lt;script type=&#34;text&amp;#x2F;javascript&#34; src=&#34;https://cdn.jsdelivr.net/npm/kity@2.0.4/dist/kity.min.js&#34;&gt;&lt;/script&gt;&lt;script type=&#34;text&amp;#x2F;javascript&#34; src=&#34;https://cdn.jsdelivr.net/npm/kityminder-core@1.4.50/dist/kityminder.core.min.js&#34;&gt;&lt;/script&gt;&lt;script defer=&#34;true&#34; type=&#34;text&amp;#x2F;javascript&#34; src=&#34;https://cdn.jsdelivr.net/npm/hexo-simple-mindmap@0.7.0/dist/mindmap.min.js&#34;&gt;&lt;/script&gt;&lt;link rel=&#34;stylesheet&#34; type=&#34;text&amp;#x2F;css&#34; href=&#34;https://cdn.jsdelivr.net/npm/hexo-simple-mindmap@0.7.0/dist/mindmap.min.css&#34;&gt;

 &lt;p&gt;&lt;img data-src=&#34;vim%E7%9A%84buffer%E3%80%81window%E3%80%81tab%E3%80%81mark%E5%92%8Cregister.assets/v2-20c4faeb143359b6da405ce558050177_r.jpg&#34; alt=&#34;preview&#34; /&gt;&lt;/p&gt;
&lt;h2 id=&#34;buffer&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#buffer&#34;&gt;#&lt;/a&gt; buffer&lt;/h2&gt;
&lt;h3 id=&#34;buffer常用的命令&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#buffer常用的命令&#34;&gt;#&lt;/a&gt; buffer 常用的命令&lt;/h3&gt;
&lt;p&gt;测试用例&lt;/p&gt;
&lt;figure class=&#34;highlight shell&#34;&gt;&lt;figcaption data-lang=&#34;Bash&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token variable&#34;&gt;$ls&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;2&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;file.txt hello.c tags&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;3&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token variable&#34;&gt;$vim&lt;/span&gt; -O file.txt hello.c tags&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;ol&gt;
&lt;li&gt;
&lt;p&gt;&lt;code&gt;:ls&lt;/code&gt;   列出所有的缓冲区&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;vim%E7%9A%84buffer%E3%80%81window%E3%80%81tab%E3%80%81mark%E5%92%8Cregister.assets/image-20220607090254433-16545637769363.png&#34; alt=&#34;image-20220607090254433&#34; /&gt;&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;&lt;code&gt;:bn&lt;/code&gt;  切换到下一个缓冲区，显示下一个文件的内容&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;vim%E7%9A%84buffer%E3%80%81window%E3%80%81tab%E3%80%81mark%E5%92%8Cregister.assets/image-20220607090421178-16545638628155.png&#34; alt=&#34;image-20220607090421178&#34; /&gt;&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;&lt;code&gt;:bp&lt;/code&gt;    切换到上一个缓冲区，显示上一个文件的内容&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;vim%E7%9A%84buffer%E3%80%81window%E3%80%81tab%E3%80%81mark%E5%92%8Cregister.assets/image-20220607090544217-16545639460127-16545639516869.png&#34; alt=&#34;image-20220607090544217&#34; /&gt;&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;vim%E7%9A%84buffer%E3%80%81window%E3%80%81tab%E3%80%81mark%E5%92%8Cregister.assets/image-20220607090656479-165456401841311.png&#34; alt=&#34;image-20220607090656479&#34; /&gt;&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;&lt;code&gt;:b number&lt;/code&gt;  切换到指定数字编号的缓冲区&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;vim%E7%9A%84buffer%E3%80%81window%E3%80%81tab%E3%80%81mark%E5%92%8Cregister.assets/image-20220607090817194.png&#34; alt=&#34;image-20220607090817194&#34; /&gt;&lt;img data-src=&#34;vim%E7%9A%84buffer%E3%80%81window%E3%80%81tab%E3%80%81mark%E5%92%8Cregister.assets/image-20220607090903592.png&#34; alt=&#34;image-20220607090903592&#34; /&gt;&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;&lt;code&gt;:b fileName&lt;/code&gt;  这里的  &lt;code&gt;fileName&lt;/code&gt;  是一个具体的文件名称，文件名称可以是正则表达式，也可以是文件名中的个别字母，一旦匹配就会加载该缓冲区，显示该文件。&lt;/p&gt;
&lt;/li&gt;
&lt;/ol&gt;
&lt;h2 id=&#34;window&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#window&#34;&gt;#&lt;/a&gt; window&lt;/h2&gt;
&lt;p&gt;使用 vim 打开文件，呈现在你眼前的文件内容就是窗口，窗口是用来查看缓冲区的内容的。你可以用多个窗口查看同一个缓冲区，也可以用多个窗口查看不同的缓冲区。&lt;/p&gt;
&lt;h2 id=&#34;tab&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#tab&#34;&gt;#&lt;/a&gt; tab&lt;/h2&gt;
&lt;h3 id=&#34;tab常用命令&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#tab常用命令&#34;&gt;#&lt;/a&gt; tab 常用命令&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;&lt;code&gt;:tabnew web&lt;/code&gt;  创建一个名为 web 的 tab&lt;/li&gt;
&lt;li&gt;&lt;code&gt;:tabc&lt;/code&gt;  关闭当前打开的 tab&lt;/li&gt;
&lt;li&gt;&lt;code&gt;:tabs&lt;/code&gt;  查看 tab 列表&lt;/li&gt;
&lt;li&gt;&lt;code&gt;gt&lt;/code&gt;  切换 tab  &lt;code&gt;ngt&lt;/code&gt;  切换到第 n 个 tab&lt;/li&gt;
&lt;/ul&gt;
&lt;h2 id=&#34;mark&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#mark&#34;&gt;#&lt;/a&gt; mark&lt;/h2&gt;
&lt;p&gt;按下键盘上的 m , 紧跟着在按下键盘上的（a-zA-Z）当中的任何一个字母，这样一个标记 （mark）例如 ma, mA 这样一个名字叫做 a 或者 A 的标记就建立起来了。&lt;/p&gt;
&lt;p&gt;例如 :&lt;/p&gt;
&lt;figure class=&#34;highlight text&#34;&gt;&lt;figcaption data-lang=&#34;text&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;ma&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;p&gt;意思在当前文件的光标所在的行建立了一个标记，以后我们可以快速定位到这个位置。&lt;/p&gt;
&lt;p&gt;&lt;strong&gt;如何激活标记？&lt;/strong&gt;&lt;/p&gt;
&lt;p&gt;使用 ‘（单引号） 或者 ` (常规键盘靠近数字键 1 左边的按键，我这里就做撇号) ，紧接着按下当初标记的那个字母就会跳到当初标记的那个位置。&lt;/p&gt;
&lt;p&gt;例如 ：`a 和 ‘a&lt;/p&gt;
&lt;p&gt;&lt;strong&gt;‘a 和 `a 有什么区别呢？&lt;/strong&gt;&lt;/p&gt;
&lt;p&gt;‘a （也就是单引号 + a） 是跳转到当初标记的行首&lt;/p&gt;
&lt;p&gt;`a (也就是撇号 + a) 实跳转到当初标记的时候光标所在的位置&lt;/p&gt;
&lt;p&gt;&lt;strong&gt;ma 和 mA 有什么区别？&lt;/strong&gt;&lt;/p&gt;
&lt;p&gt;如果要是在文件之间跳转要使用大写的标记才可以，例如现在在当前文件的某处打了一个标记 mA , 离开该文件切换到了另一个文件，此时使用 ‘A 就可以返回之前文件打标记的地方了。&lt;/p&gt;
&lt;p&gt;&lt;strong&gt;结论：小写字母通常用来单个文件坐标记，大写字母通常是用来文件间坐标记。&lt;/strong&gt;&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;&lt;code&gt;:marks&lt;/code&gt;  列出所有标记&lt;/li&gt;
&lt;li&gt;&lt;code&gt;:delmarks a&lt;/code&gt;  删除标记 a&lt;/li&gt;
&lt;li&gt;&lt;code&gt;:delmarks!&lt;/code&gt;  删除所有的标记&lt;/li&gt;
&lt;/ul&gt;
&lt;h2 id=&#34;register&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#register&#34;&gt;#&lt;/a&gt; register&lt;/h2&gt;
&lt;p&gt;vim 也有相似的逻辑，当我们使用 y 复制内容的时候，vim 默认把内容寄存到一个无名寄存器，当使用黏贴功能 p 的时候，就会默认从无名寄存器中取出内容。&lt;/p&gt;
&lt;p&gt;vim 通常使用 “（双引号）加上一个 a-z 的字母来给定义一个有名字的寄存器。&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;&lt;code&gt;&amp;quot;ayy&lt;/code&gt;  将内容赋值到 a 寄存器中&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;&lt;code&gt;&amp;quot;ap&lt;/code&gt;  从寄存器 a 中获取内容&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;&lt;code&gt;:reg&lt;/code&gt;  列出所有寄存器&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;&lt;code&gt;:reg a&lt;/code&gt;  查看寄存器 a 中的内容&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;&lt;code&gt;&amp;quot;&amp;quot;&lt;/code&gt;  双引号表示无名寄存器&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;script type=&#34;text&amp;#x2F;javascript&#34; src=&#34;https://cdn.jsdelivr.net/npm/kity@2.0.4/dist/kity.min.js&#34;&gt;&lt;/script&gt;&lt;script type=&#34;text&amp;#x2F;javascript&#34; src=&#34;https://cdn.jsdelivr.net/npm/kityminder-core@1.4.50/dist/kityminder.core.min.js&#34;&gt;&lt;/script&gt;&lt;script defer=&#34;true&#34; type=&#34;text&amp;#x2F;javascript&#34; src=&#34;https://cdn.jsdelivr.net/npm/hexo-simple-mindmap@0.7.0/dist/mindmap.min.js&#34;&gt;&lt;/script&gt;&lt;link rel=&#34;stylesheet&#34; type=&#34;text&amp;#x2F;css&#34; href=&#34;https://cdn.jsdelivr.net/npm/hexo-simple-mindmap@0.7.0/dist/mindmap.min.css&#34;&gt;

 &lt;p&gt;noremap 为不递归地映射按键 (hjkl iIu)&lt;/p&gt;
&lt;p&gt;map&lt;/p&gt;
&lt;p&gt;&amp;lt;nop&amp;gt; !p&lt;/p&gt;
&lt;p&gt;:w&amp;lt;CR&amp;gt; :w center 键&lt;/p&gt;
&lt;p&gt;:q&amp;lt;CR&amp;gt; :q center 键&lt;/p&gt;
&lt;p&gt;set number 设置行号&lt;/p&gt;
&lt;p&gt;set norelativenumber 关闭相关行号&lt;/p&gt;
&lt;p&gt;set cursorline  显示当前位置&lt;/p&gt;
&lt;p&gt;set wrap&lt;/p&gt;
&lt;p&gt;set showcmd&lt;/p&gt;
&lt;p&gt;set wildmenu&lt;/p&gt;
&lt;p&gt;c 修改&lt;/p&gt;
&lt;p&gt;c +nu+left/right&lt;/p&gt;
&lt;p&gt;c+i+&amp;quot;/{&lt;/p&gt;
&lt;p&gt;f + 要查找的字符  找到当前行要查找的字符&lt;/p&gt;
&lt;p&gt;set hlsearch 搜索高亮&lt;/p&gt;
&lt;p&gt;set incsearch 写入高亮&lt;/p&gt;
&lt;p&gt;set smartcase 只能大小写&lt;/p&gt;
&lt;p&gt;v 可视普通模式&lt;/p&gt;
&lt;p&gt;V 可视行模式&lt;/p&gt;
&lt;p&gt;&amp;lt;C-v&amp;gt; 可视块模式&lt;/p&gt;
&lt;p&gt;&amp;lt;C-v&amp;gt;+G + I + 要添加的字符    表示在光标所在列之前插入你要添加的字符&lt;/p&gt;
&lt;p&gt;:set splitright&lt;/p&gt;
&lt;p&gt;:set nosplitright&lt;/p&gt;
&lt;p&gt;:set nosplitbelow&lt;/p&gt;
&lt;p&gt;:set splitbelow&lt;/p&gt;
&lt;p&gt;:res+number 增加当前窗口的宽度&lt;/p&gt;
&lt;p&gt;:res-number 减少当前窗口的宽度&lt;/p&gt;
&lt;p&gt;:vertical resize +number 增加当前窗口的高度&lt;/p&gt;
&lt;p&gt;:vertical resize-number 减少当前窗口的高度&lt;/p&gt;
&lt;p&gt;:tabe 打开新的标签页&lt;/p&gt;
&lt;p&gt;:-tabnext 到左边的标签页&lt;/p&gt;
&lt;p&gt;:+tabnext 到右边的标签页&lt;/p&gt;
&lt;script type=&#34;text&amp;#x2F;javascript&#34; src=&#34;https://cdn.jsdelivr.net/npm/kity@2.0.4/dist/kity.min.js&#34;&gt;&lt;/script&gt;&lt;script type=&#34;text&amp;#x2F;javascript&#34; src=&#34;https://cdn.jsdelivr.net/npm/kityminder-core@1.4.50/dist/kityminder.core.min.js&#34;&gt;&lt;/script&gt;&lt;script defer=&#34;true&#34; type=&#34;text&amp;#x2F;javascript&#34; src=&#34;https://cdn.jsdelivr.net/npm/hexo-simple-mindmap@0.7.0/dist/mindmap.min.js&#34;&gt;&lt;/script&gt;&lt;link rel=&#34;stylesheet&#34; type=&#34;text&amp;#x2F;css&#34; href=&#34;https://cdn.jsdelivr.net/npm/hexo-simple-mindmap@0.7.0/dist/mindmap.min.css&#34;&gt;

 &lt;h2 id=&#34;youcompleteme插件&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#youcompleteme插件&#34;&gt;#&lt;/a&gt; YouCompleteMe 插件&lt;/h2&gt;
&lt;h3 id=&#34;youcompleteme命令&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#youcompleteme命令&#34;&gt;#&lt;/a&gt; YouCompleteMe 命令&lt;/h3&gt;
&lt;h4 id=&#34;ycm全局命令&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#ycm全局命令&#34;&gt;#&lt;/a&gt; YCM 全局命令&lt;/h4&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;&lt;code&gt;:YcmRestartServer&lt;/code&gt;&lt;/p&gt;
&lt;p&gt;重新启动 &lt;code&gt;ycmd completion&lt;/code&gt;  服务器，当该服务器由于某些原因被停止，可以使用该命令&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;&lt;code&gt;:YcmFocusCompileAndDiagnostics&lt;/code&gt;&lt;/p&gt;
&lt;p&gt;强制 YCM 立刻重新编译你的文件并展示并显示任何遇到的新诊断。需要注意的是：用这个命令来重新编译，会阻塞 Vim GUI 一段时间&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;&lt;code&gt;:YcmDiags&lt;/code&gt;&lt;/p&gt;
&lt;p&gt;如果在你的文件中检测到错误或警告，则将错误或警告放入到 vim 的 &lt;code&gt;locationlist&lt;/code&gt;  中并将其打开。如果一个错误或警告能够用命令 &lt;code&gt;:YcmCompleter FixIt&lt;/code&gt;  修复，那么 &lt;code&gt;FixIt available&lt;/code&gt;  会被追加到这个错误或警告文本的后面。需要注意的是， &lt;code&gt;FixIt available&lt;/code&gt;  的缺失并不是严格意义上的修复 —— 它是不可用的，应为并不是所有的补全程序都能提供这个提示。可以使用 &lt;code&gt;g:ycm_open_locallist_on_ycm_diags&lt;/code&gt;  这个选项来阻止这个 &lt;code&gt;location list&lt;/code&gt;  打开，但是仍然会在当中填充新的诊断数据&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;&lt;code&gt;:YcmShowDetailDiagnostic&lt;/code&gt;&lt;/p&gt;
&lt;p&gt;显示所有的诊断数据&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;&lt;code&gt;:YcmDebugInfo&lt;/code&gt;&lt;/p&gt;
&lt;p&gt;打印当前文件的各种调试信息&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;&lt;code&gt;:YcmToggleLogs&lt;/code&gt;&lt;/p&gt;
&lt;p&gt;这个命令为当前文件类型提交由 YCM,ycmd 服务器，和语义引擎服务器创建的日志文件列表。这些日志文件能够在编辑器中通过确定对应的数字或用鼠标点击它来打开。此外，这个命令还能够将日志文件的名称作为参数，也就是说，用该命令打开指定的日志文件&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;&lt;code&gt;:YcmCompleter&lt;/code&gt;&lt;/p&gt;
&lt;p&gt;这条命令在 YCM 中提供大量的类 IDE 特性，如语义 GoTo, 类型信息，修复信息，重构。该命令接受一个范围，该范围可以通过 Vim 的一种可视化模式 (参见:h visual-use) 中的选择来指定，也可以在命令行上指定。&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;h3 id=&#34;ycmcompleter-子命令&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#ycmcompleter-子命令&#34;&gt;#&lt;/a&gt; YcmCompleter 子命令&lt;/h3&gt;
&lt;p&gt;已被调用的子命令会自动的被路由到当前激活的语义补全程序，因此，如果当前活动文件是一个 python 文件， &lt;code&gt;:YcmCompleter GoToDefinition&lt;/code&gt;  将在 Python 语义补全程序中调用 &lt;code&gt;GoToDefinition&lt;/code&gt;  子命令，如果是一个 C 族语言文件，将在 clang 补全程序程序中调用 &lt;code&gt;GoToDefinition&lt;/code&gt;  子命令。&lt;/p&gt;
&lt;h4 id=&#34;goto-命令&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#goto-命令&#34;&gt;#&lt;/a&gt; GoTo 命令&lt;/h4&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;&lt;code&gt;GoToInclude&lt;/code&gt;  查找当前文件的头文件并跳转到头文件的位置&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;支持的文件类型： &lt;code&gt;c,cpp,objc,objcpp,cuda&lt;/code&gt;&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;&lt;code&gt;GoToDeclaration&lt;/code&gt;  查找游标所在的标识符并跳转到它的声明&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;支持的文件类型:  &lt;code&gt;c,cpp,objc,objcpp,cuda,cs,go&lt;/code&gt;   &lt;code&gt;java,javascript,python,rust,typescript&lt;/code&gt;&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;&lt;code&gt;GoToDefinition&lt;/code&gt;  查找光标所在的标识符并跳转到它的定义出&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;注意： 对于 C 族语言来说，当标识符的定义是在当前的转换单元中，只有在确定的环境中才能够有效。一个转换单元由当前编辑的所有文件以及用 &lt;code&gt;#include&lt;/code&gt; （直接或间接）包含的所有文件组成。&lt;/li&gt;
&lt;li&gt;支持的文件类型： &lt;code&gt;c,cpp,objc,objcpp,cuda,cs,go&lt;/code&gt;   &lt;code&gt;java,javascript,python,rust,typescript&lt;/code&gt;&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;&lt;code&gt;GoTo&lt;/code&gt;  这个命令尝试执行他所能执行的 “最合理” 的 GoTo 操作。当前，意味着他将尝试去查找光标所在标识符并跳转到它可能拥有的所有定义；如果这个定义在当前转换单元中是不可访问的，则跳转到标识符的声明处。对于 C 族语言而言，它首先查找当前头文件并跳转，对于 Csharp 而言，实现也会被考虑和优先处理。&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;支持的文件类型： &lt;code&gt;c,cpp,objc,objcpp,cuda,cs,go&lt;/code&gt;   &lt;code&gt;java,javascript,python,rust,typescript&lt;/code&gt;&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;&lt;code&gt;GoToImprecise&lt;/code&gt;  这个命令与 &lt;code&gt;GoTo&lt;/code&gt;  命令类似，除了在 AST 中查找到结点之前，不能够用 &lt;code&gt;libclang&lt;/code&gt;  重编译这个文件。当您编辑需要长时间编译的文件，但您知道自上次解析以来没有进行任何会导致错误跳转的更改时，这可能非常有用。当您只是浏览代码库时，这个命令可以节省相当多的延迟时间。&lt;/p&gt;
&lt;blockquote&gt;
&lt;h2 id=&#34;这个命令用正确性换取速度&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#这个命令用正确性换取速度&#34;&gt;#&lt;/a&gt; 这个命令用正确性换取速度！&lt;/h2&gt;
&lt;/blockquote&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;&lt;code&gt;GoToSymbol &amp;lt;symbol query&amp;gt;&lt;/code&gt;  查找匹配到指定字符的所有标识符的定义。注意，这没有使用任何类型的智能 / 模糊匹配。但是，可以使用交互式符号搜索。&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;支持的文件类型： &lt;code&gt;c,cpp,objc,objcpp,cuda,cs,go&lt;/code&gt;   &lt;code&gt;java,javascript,python,rust,typescript&lt;/code&gt;&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;&lt;code&gt;GoToImplementation&lt;/code&gt;  它不支持 C 族语言&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;&lt;code&gt;GoToImplementationElseDeclaration&lt;/code&gt;  仅 Csharp 支持&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;&lt;code&gt;GoToType&lt;/code&gt;  仅 &lt;code&gt;go,java,javascript,typescript&lt;/code&gt;  支持&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;&lt;code&gt;GoToDucumentOutline&lt;/code&gt;  在当前文件中提供一个标识符列表，存放在在 quickfix list 列表中。&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;h4 id=&#34;语义信息命令&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#语义信息命令&#34;&gt;#&lt;/a&gt; 语义信息命令&lt;/h4&gt;
&lt;p&gt;这些命令查找代码的静态信息是非常有用的，例如变量的类型，显示声明和文档字符串&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;&lt;code&gt;GetType&lt;/code&gt;  回显游标下的变量或方法的类型，不同的地方是派生类型。
&lt;ul&gt;
&lt;li&gt;支持的文件类型： &lt;code&gt;c,cpp,objc,objcpp,cuda,cs,go&lt;/code&gt;   &lt;code&gt;java,javascript,python,rust,typescript&lt;/code&gt;&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;&lt;code&gt;GetTypeImprecise&lt;/code&gt;  与 &lt;code&gt;GetType&lt;/code&gt;  命令类似&lt;/li&gt;
&lt;li&gt;&lt;code&gt;GetParent&lt;/code&gt;   回显当前游标所在标识符的上一级信息&lt;/li&gt;
&lt;li&gt;&lt;code&gt;GetDoc&lt;/code&gt;  显示预览窗口，显示关于光标下标识符的快速信息。依赖的文件类型如下所示：
&lt;ul&gt;
&lt;li&gt;类型或声明的标识符&lt;/li&gt;
&lt;li&gt;Doxygen/javadoc 注释&lt;/li&gt;
&lt;li&gt;Python docstrings&lt;/li&gt;
&lt;li&gt;etc&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;&lt;code&gt;GetDocImprecise&lt;/code&gt;  与 &lt;code&gt;GetDoc&lt;/code&gt;  类似&lt;/li&gt;
&lt;/ul&gt;
&lt;h4 id=&#34;重构命令&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#重构命令&#34;&gt;#&lt;/a&gt; 重构命令&lt;/h4&gt;
&lt;p&gt;这些命令对源代码进行更改，以便执行重构或代码纠正。YouCompleteMe 不执行任何不能撤消的操作，并且从不保存或写入文件到磁盘。&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;&lt;code&gt;FixIt&lt;/code&gt;  在可能的情况下，尝试对缓冲区进行更改以纠正当前行上的诊断。当有多个建议可用时 (例如有多种方法来解决给定的警告，或报告当前行的多个诊断)，将显示选项，并可以选择一个。提供诊断的补全器也可能对源进行微小的修改，以纠正诊断结果。示例包括语法错误，如缺少结尾分号、虚假字符，或语义引擎可以确定地建议更正的其他错误。如果对当前行没有可用的 fix-it，或者对当前行没有诊断，则该命令对当前缓冲区没有影响。如果进行了任何修改，对缓冲区所做的修改的数量将被回显，用户可以使用编辑器的 undo 命令来恢复。当诊断可用，并且 &lt;code&gt;g:ycm_echo_current_diagnostic&lt;/code&gt;  被设置为 1 时，当补全器能够添加这个指示时，文本 (FixIt) 被添加到回显的诊断。文本 (可用 FixIt) 还被附加到 &lt;code&gt;:ycmdaigs&lt;/code&gt;  命令的输出中的诊断文本中，用于任何具有可用 fix-its 的诊断 (补全程序可以提供此指示)。&lt;/li&gt;
&lt;/ul&gt;
&lt;h4 id=&#34;多文件重构&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#多文件重构&#34;&gt;#&lt;/a&gt; 多文件重构&lt;/h4&gt;
&lt;p&gt;当一个 Refactor 或 FixIt 命令触及多个文件时，YouCompleteMe 尝试将这些修改应用到当前选项卡中任何现有的打开的、可见的缓冲区。如果找不到这样的缓冲区，YouCompleteMe 在当前窗口的顶部以一个新的小的水平分割打开文件，应用更改，然后隐藏窗口。注意：缓冲区保持打开，必须手动保存。在执行此操作之前会打开一个确认对话框，以提醒您即将发生此操作。&lt;/p&gt;
&lt;p&gt;修改完成后， &lt;code&gt;quickfix list&lt;/code&gt;  (参见:help quickfix) 将填充所有修改的位置。这可以用来检查通过使用:copen 所做的所有自动更改。通常，使用 CTRL-W 组合在新的拆分中打开所选文件。可以使用 YcmQuickFixOpened 自动命令来定制快速修复窗口的打开方式。&lt;/p&gt;
&lt;p&gt;缓冲区不会自动保存。也就是说，在从快速修复列表查看更改之后，必须手动保存修改的缓冲区。可以使用 Vim 强大的撤销功能撤消更改 (参见：帮助撤销)。注意，Vim 的撤消是针对每个缓冲区的，因此要撤消所有更改，必须在每个修改的缓冲区中分别应用撤消命令。&lt;/p&gt;
&lt;p&gt;注意：在应用修改时，Vim 可能会找到已经打开并具有交换文件的文件。如果在任何此类提示中选择 Abort 或 Quit，则该命令将被终止。这使得 Refactor 操作只完成了一部分，必须使用 Vim 的撤消特性手动纠正。在这种情况下，没有填充快速修复列表。Inspect:buffers 或等价的 (参见:help buffers) 以查看被命令打开的缓冲区。&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;&lt;code&gt;Format&lt;/code&gt;  该命令根据 Vim 选项的 shiftwidth 和 expandtab 的值格式化整个缓冲区或其中的一部分 (分别参见:h&#39;sw&#39; 和:h et)。要格式化文档的特定部分，您可以在 Vim 的一种可视化模式中选择它 (参见:h visual-use) 并运行命令或直接在命令行上输入范围，例如：2,5ycmcompleter format 来格式化它从第 2 行到第 5 行。&lt;/li&gt;
&lt;/ul&gt;
&lt;h3 id=&#34;youcompleteme函数&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#youcompleteme函数&#34;&gt;#&lt;/a&gt; YouCompleteMe 函数&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;&lt;code&gt;youcompleteme#GetErrorCount&lt;/code&gt;  函数&lt;/p&gt;
&lt;p&gt;获取 YCM 诊断错误信息数，如果没有错误信息，则返回 0&lt;/p&gt;
&lt;figure class=&#34;highlight c&#34;&gt;&lt;figcaption data-lang=&#34;c&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;call youcompleteme#&lt;span class=&#34;token function&#34;&gt;GetErrorCount&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;&lt;code&gt;youcompleteme#GetWarningCount&lt;/code&gt;  函数&lt;/p&gt;
&lt;p&gt;获取 YCM 诊断警告信息数，如果没有警告信息，则返回 0&lt;/p&gt;
&lt;figure class=&#34;highlight shell&#34;&gt;&lt;figcaption data-lang=&#34;Bash&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;call youcompleteme&lt;span class=&#34;token comment&#34;&gt;#GetWarningCount()&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;&lt;code&gt;youcompleteme#GetCommandResponse(...)&lt;/code&gt;  函数&lt;/p&gt;
&lt;p&gt;运行补全子命令并以字符串形式返回结果。这可能很有用，例如在一个弹出窗口中显示 GetGoc 输出&lt;/p&gt;
&lt;figure class=&#34;highlight shell&#34;&gt;&lt;figcaption data-lang=&#34;Bash&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token builtin class-name&#34;&gt;let&lt;/span&gt; s:ycm_hover_popup &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; -1&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;2&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;function&lt;/span&gt; s:Hover&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;3&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;  &lt;span class=&#34;token builtin class-name&#34;&gt;let&lt;/span&gt; response &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; youcompleteme&lt;span class=&#34;token comment&#34;&gt;#GetCommandResponse(&#39;GetDoc&#39;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;4&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;  &lt;span class=&#34;token keyword&#34;&gt;if&lt;/span&gt; response &lt;span class=&#34;token operator&#34;&gt;==&lt;/span&gt; &lt;span class=&#34;token string&#34;&gt;&#39;&#39;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;5&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token builtin class-name&#34;&gt;return&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;6&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;  endif&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;7&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;  &lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;8&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;  call popup_hid&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;s:ycm_hover_popup&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;9&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;  &lt;span class=&#34;token builtin class-name&#34;&gt;let&lt;/span&gt; s:ycm_hover_popup &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; popup_atcursor&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt; balloon_split&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt; response &lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;, &lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;10&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;endfunction&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;11&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;12&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token string&#34;&gt;&#34; CursorHold triggers in normal mode after a delay&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;13&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;autocmd CursorHold * call s:Hover()&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;14&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;15&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&#34;&lt;/span&gt; or,if you prefer, a mapping&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;16&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;nnoremap &lt;span class=&#34;token operator&#34;&gt;&amp;lt;&lt;/span&gt;silent&lt;span class=&#34;token operator&#34;&gt;&gt;&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;&amp;lt;&lt;/span&gt;leader&lt;span class=&#34;token operator&#34;&gt;&gt;&lt;/span&gt;D :call &lt;span class=&#34;token operator&#34;&gt;&amp;lt;&lt;/span&gt;SID&lt;span class=&#34;token operator&#34;&gt;&gt;&lt;/span&gt;Hover&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;&amp;lt;&lt;/span&gt;CR&lt;span class=&#34;token operator&#34;&gt;&gt;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;/li&gt;
&lt;/ul&gt;
&lt;h2 id=&#34;ctags&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#ctags&#34;&gt;#&lt;/a&gt; Ctags&lt;/h2&gt;
&lt;h3 id=&#34;ctags的安装&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#ctags的安装&#34;&gt;#&lt;/a&gt; Ctags 的安装&lt;/h3&gt;
&lt;figure class=&#34;highlight shell&#34;&gt;&lt;figcaption data-lang=&#34;Bash&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token variable&#34;&gt;$sudo&lt;/span&gt; &lt;span class=&#34;token function&#34;&gt;apt&lt;/span&gt; &lt;span class=&#34;token function&#34;&gt;install&lt;/span&gt; ctags&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;h3 id=&#34;ctags的使用&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#ctags的使用&#34;&gt;#&lt;/a&gt; Ctags 的使用&lt;/h3&gt;
&lt;h4 id=&#34;第一-生成索引文件&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#第一-生成索引文件&#34;&gt;#&lt;/a&gt; 第一、生成索引文件&lt;/h4&gt;
&lt;figure class=&#34;highlight shell&#34;&gt;&lt;figcaption data-lang=&#34;Bash&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token variable&#34;&gt;$ctags&lt;/span&gt; -R --c++-kinds&lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt;+px --fields&lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt;+iaS --extra&lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt;+q&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;2&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token comment&#34;&gt;# --c++-kinds=+px 为记录 C++ 文件中的函数声明和各种外部和向前声明 &lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;3&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token comment&#34;&gt;# --fields 为 ctags 要求描述的信息&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;4&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token comment&#34;&gt;# +iaS&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;5&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token comment&#34;&gt;# i 标识如果有继承，则标识父类&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;6&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token comment&#34;&gt;# a 如果元素是类成员，要标明其调用权限&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;7&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token comment&#34;&gt;# S 如果是函数，则标识函数的 signature&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;8&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token comment&#34;&gt;# --extra=+q&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;h4 id=&#34;第二-加载tags索引文件&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#第二-加载tags索引文件&#34;&gt;#&lt;/a&gt; 第二、加载 tags 索引文件&lt;/h4&gt;
&lt;p&gt;在 vim 的命令行模式下输入如下命令&lt;/p&gt;
&lt;figure class=&#34;highlight shell&#34;&gt;&lt;figcaption data-lang=&#34;Bash&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;:set &lt;span class=&#34;token assign-left variable&#34;&gt;tags&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt;path/to/tags&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;2&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;:set autochdir&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;h4 id=&#34;第三-跳转&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#第三-跳转&#34;&gt;#&lt;/a&gt; 第三、跳转&lt;/h4&gt;
&lt;ul&gt;
&lt;li&gt;&lt;code&gt;&amp;lt;C-]&amp;gt;&lt;/code&gt;  跳转到声明处或定义处&lt;/li&gt;
&lt;li&gt;&lt;code&gt;&amp;lt;C-t&amp;gt;&lt;/code&gt;  跳回到原来的位置&lt;/li&gt;
&lt;li&gt;&lt;code&gt;:ts&lt;/code&gt;  显示 tags list&lt;/li&gt;
&lt;li&gt;&lt;code&gt;:tp&lt;/code&gt;  上一个 tag&lt;/li&gt;
&lt;li&gt;&lt;code&gt;:tn&lt;/code&gt;  下一个 tag&lt;/li&gt;
&lt;/ul&gt;
&lt;h2 id=&#34;cscope&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#cscope&#34;&gt;#&lt;/a&gt; cscope&lt;/h2&gt;
&lt;h3 id=&#34;安装cscope&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#安装cscope&#34;&gt;#&lt;/a&gt; 安装 cscope&lt;/h3&gt;
&lt;figure class=&#34;highlight shell&#34;&gt;&lt;figcaption data-lang=&#34;Bash&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token variable&#34;&gt;$sudo&lt;/span&gt; &lt;span class=&#34;token function&#34;&gt;apt&lt;/span&gt; &lt;span class=&#34;token function&#34;&gt;install&lt;/span&gt; cscope&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;h3 id=&#34;使用cscope&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#使用cscope&#34;&gt;#&lt;/a&gt; 使用 cscope&lt;/h3&gt;
&lt;h4 id=&#34;第一-创建cscope数据库&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#第一-创建cscope数据库&#34;&gt;#&lt;/a&gt; 第一、创建 cscope 数据库&lt;/h4&gt;
&lt;figure class=&#34;highlight shell&#34;&gt;&lt;figcaption data-lang=&#34;Bash&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token variable&#34;&gt;$cscope&lt;/span&gt; -Rbq &lt;span class=&#34;token builtin class-name&#34;&gt;.&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;h4 id=&#34;第二-加载cscope数据库&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#第二-加载cscope数据库&#34;&gt;#&lt;/a&gt; 第二、加载 cscope 数据库&lt;/h4&gt;
&lt;h5 id=&#34;自动加载cscope数据库&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#自动加载cscope数据库&#34;&gt;#&lt;/a&gt; 自动加载 cscope 数据库&lt;/h5&gt;
&lt;p&gt;在.vimrc 中编写自动脚本，如下所示：&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-sh&#34;&gt;if has(&amp;quot;cscope&amp;quot;) &amp;quot; 查看是否有cscope这个应用程序
  if filereable(&amp;quot;cscope.put&amp;quot;) &amp;quot; 是否能读取到cscope数据库
     cs add cscope.out &amp;quot; 如果能够读取到当前数据库，就加载数据库
  else &amp;quot; 在其他的地方搜索能够使用的数据库
    let cscope_file=findfile(&amp;quot;cscope.out&amp;quot;, &amp;quot;.;&amp;quot;)
    let cscope_pre=mathchstr(cscope_file,&amp;quot;.*/&amp;quot;)
    if !empty(cscope_file) &amp;amp;&amp;amp; filereadable(cscope_file)
       set nocsverb
       exe &amp;quot;cs add&amp;quot; cscope_file cscope_pre
       set csverb
    endif
  endif
endif
&lt;/code&gt;&lt;/pre&gt;
&lt;h5 id=&#34;手动加载cscope数据库&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#手动加载cscope数据库&#34;&gt;#&lt;/a&gt; 手动加载 cscope 数据库&lt;/h5&gt;
&lt;p&gt;在 vim 的命令行模式下，输入如下命令&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-sh&#34;&gt;:cs add path/to/cscope.out
&lt;/code&gt;&lt;/pre&gt;
&lt;h4 id=&#34;第三-cscope常用的命令&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#第三-cscope常用的命令&#34;&gt;#&lt;/a&gt; 第三、cscope 常用的命令&lt;/h4&gt;
&lt;pre&gt;&lt;code class=&#34;language-sh&#34;&gt;：cs f s ---- 查找C语言符号，即查找函数名、宏、枚举值等出现的地方
：cs f g ---- 查找函数、宏、枚举等定义的位置，类似ctags所提供的功能
：cs f d ---- 查找本函数调用的函数
：cs f c ---- 查找调用本函数的函数
：cs f t ---- 查找指定的字符串
：cs f e ---- 查找egrep模式，相当于egrep功能，但查找速度快多了
：cs f f ---- 查找并打开文件，类似vim的find功能
：cs f i ---- 查找包含本文件的文
&lt;/code&gt;&lt;/pre&gt;
&lt;pre&gt;&lt;code class=&#34;language-sh&#34;&gt;-R: 在生成索引文件时，搜索子目录树中的代码 
-b: 只生成索引文件，不进入cscope的界面 
-q: 生成cscope.in.out和cscope.po.out文件，加快cscope的索引速度 
-k: 在生成索引文件时，不搜索/usr/include目录 
-i: 如果保存文件列表的文件名不是cscope.files时，需要加此选项告诉cscope到哪儿去找源文件列表。可以使用”-“，表示由标准输入获得文件列表。 
-Idir: 在-I选项指出的目录中查找头文件 
-u: 扫描所有文件，重新生成交叉索引文件 
-C: 在搜索时忽略大小写 
-Ppath: 在以相对路径表示的文件前加上的path，这样，你不用切换到你数据库文件所在的目录也可以使用它了。 
&lt;/code&gt;&lt;/pre&gt;
&lt;h2 id=&#34;rainbow插件&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#rainbow插件&#34;&gt;#&lt;/a&gt; rainbow 插件&lt;/h2&gt;
&lt;h2 id=&#34;nerdcommenter插件&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#nerdcommenter插件&#34;&gt;#&lt;/a&gt; NERDCommenter 插件&lt;/h2&gt;
&lt;h3 id=&#34;配置&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#配置&#34;&gt;#&lt;/a&gt; 配置&lt;/h3&gt;
&lt;pre&gt;&lt;code class=&#34;language-sh&#34;&gt;&amp;quot; Create default mappings
let g:NERDCreateDefaultMappings = 1

&amp;quot; Add spaces after comment delimiters by default
let g:NERDSpaceDelims = 1

&amp;quot; Use compact syntax for prettified multi-line comments
let g:NERDCompactSexyComs = 1

&amp;quot; Align line-wise comment delimiters flush left instead of following code indentation
let g:NERDDefaultAlign = &#39;left&#39;

&amp;quot; Set a language to use its alternate delimiters by default
let g:NERDAltDelims_java = 1

&amp;quot; Add your own custom formats or override the defaults
let g:NERDCustomDelimiters = &amp;#123; &#39;c&#39;: &amp;#123; &#39;left&#39;: &#39;/**&#39;,&#39;right&#39;: &#39;*/&#39; &amp;#125; &amp;#125;

&amp;quot; Allow commenting and inverting empty lines (useful when commenting a region)
let g:NERDCommentEmptyLines = 1

&amp;quot; Enable trimming of trailing whitespace when uncommenting
let g:NERDTrimTrailingWhitespace = 1

&amp;quot; Enable NERDCommenterToggle to check all selected lines is commented or not 
let g:NERDToggleCheckAllLines = 1
&lt;/code&gt;&lt;/pre&gt;
&lt;h3 id=&#34;默认快捷键&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#默认快捷键&#34;&gt;#&lt;/a&gt; 默认快捷键&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;&lt;code&gt;[count]&amp;lt;leader&amp;gt;cc&lt;/code&gt;   等价于 在可视模式下使用 &lt;code&gt;:NERDCommenterComment&lt;/code&gt;  在可视模式下注释当前行或选中的文本&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;&lt;code&gt;[count]&amp;lt;leader&amp;gt;cn&lt;/code&gt;  等价于  &lt;code&gt;:NERDComenterNested&lt;/code&gt;  和上面的命令类似，不过它强制嵌套，即注释依然可以添加注释&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;&lt;code&gt;[count]&amp;lt;leader&amp;gt;c&amp;lt;sapce&amp;gt;&lt;/code&gt;  等价于  &lt;code&gt;:NERDCommenterToggle&lt;/code&gt;  切换所选行的注释状态。如果对最上面的选中行进行了注释，则所有选中的行都不进行注释，反之亦然。&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;&lt;code&gt;[count]&amp;lt;leader&amp;gt;cm&lt;/code&gt;  等价于  &lt;code&gt;:NERDCommenterMinimal&lt;/code&gt; ‎仅使用一组多部分分隔符注释给定的行。‎&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;&lt;code&gt;[count]&amp;lt;leader&amp;gt;ci&lt;/code&gt;  等价于  &lt;code&gt;:NERDCommenterInvert&lt;/code&gt;  ‎单独切换所选行的注释状态。‎&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;&lt;code&gt;[count]&amp;lt;leader&amp;gt;cs&lt;/code&gt;  等价于  &lt;code&gt;:NERDCommenterSexy&lt;/code&gt; ‎使用漂亮的块格式布局注释掉所选行。‎&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;&lt;code&gt;[count]&amp;lt;leader&amp;gt;cy&lt;/code&gt;  等价于  &lt;code&gt;:NERDCommenterYank&lt;/code&gt;  与 &lt;code&gt;cc&lt;/code&gt;  类似，不同之处在于，先删除已经注释的行&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;&lt;code&gt;&amp;lt;leader&amp;gt;c$&lt;/code&gt;  等价 &lt;code&gt;:NERDCommenterToEOL&lt;/code&gt;  从当前注释到最后一行&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;&lt;code&gt;&amp;lt;lader&amp;gt;cA&lt;/code&gt;  等价  &lt;code&gt;:NERDCommenterAppend&lt;/code&gt;  将注释分隔符添加到行尾，并在它们之间进入插入模式。&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;&lt;code&gt;:NERDCommenterInsert&lt;/code&gt;  在当前光标位置添加注释分隔符，并在两者之间插入。默认情况下禁用。&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;&lt;code&gt;&amp;lt;leader&amp;gt;ca&lt;/code&gt;  等价  &lt;code&gt;:NERDCommenterAltDelims&lt;/code&gt;  切换到另一组分隔符。&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;&lt;code&gt;[count]&amp;lt;leader&amp;gt;cl&lt;/code&gt;  等价  &lt;code&gt;:NERDCommenterAliginLeft&lt;/code&gt;&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;&lt;code&gt;[count]&amp;lt;leader&amp;gt;cb&lt;/code&gt;  等价于  &lt;code&gt;:NERDCommenterAlignBoth&lt;/code&gt;&lt;/p&gt;
&lt;p&gt;cl 和 cb 与 cc 类似，只不过注释的对齐方式不同而已。&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;&lt;code&gt;[count]&amp;lt;leader&amp;gt;cu&lt;/code&gt;  等价于  &lt;code&gt;:NERDCommenterUncomment&lt;/code&gt;  取消所选行的注释&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;除了 &lt;code&gt;:NERDComenterInsert&lt;/code&gt;  以外，其他的所有注释命令既可以在普通模式下使用也可以在可视模式下使用&lt;/p&gt;
&lt;p&gt;&lt;code&gt;cc cn cl cb cy&lt;/code&gt;  都单行单行的注释，只是对其方式不同而已&lt;/p&gt;
&lt;p&gt;&lt;code&gt;cm&lt;/code&gt;  是块注释&lt;/p&gt;
&lt;p&gt;&lt;code&gt;ci&lt;/code&gt;  切换注释的形式，如果是单行注释，则切换到块注释，否则反之&lt;/p&gt;
&lt;p&gt;&lt;code&gt;cs&lt;/code&gt;  用美化的注释块进行注释&lt;/p&gt;
&lt;p&gt;&lt;code&gt;c&amp;lt;space&amp;gt;&lt;/code&gt;  如果光标所在行没有注释，而在它下面的部分行无论有没有注释，则所选中的所有行都进行注释；如果光标所在行有注释，反之。&lt;/p&gt;
&lt;p&gt;以上所有的命令只有 &lt;code&gt;&amp;lt;leader&amp;gt;&lt;/code&gt;  按下后才能才能开始按他们&lt;/p&gt;
&lt;p&gt;&lt;code&gt;c$&lt;/code&gt;  从当前行开始注释到最后一行&lt;/p&gt;
&lt;p&gt;&lt;code&gt;ca&lt;/code&gt;  切换注释符&lt;/p&gt;
&lt;p&gt;&lt;code&gt;cA&lt;/code&gt;  在行尾添加一个注释&lt;/p&gt;
&lt;h2 id=&#34;vim-terminal-help插件&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#vim-terminal-help插件&#34;&gt;#&lt;/a&gt; vim-terminal-help 插件&lt;/h2&gt;
&lt;h3 id=&#34;快捷键使用方式&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#快捷键使用方式&#34;&gt;#&lt;/a&gt; 快捷键使用方式&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;&lt;code&gt;ALT&lt;/code&gt;  +  &lt;code&gt;=&lt;/code&gt; : toggle terminal below.&lt;/li&gt;
&lt;li&gt;&lt;code&gt;ALT&lt;/code&gt;  +  &lt;code&gt;SHIFT&lt;/code&gt;  +  &lt;code&gt;h&lt;/code&gt; : move to the window on the left.&lt;/li&gt;
&lt;li&gt;&lt;code&gt;ALT&lt;/code&gt;  +  &lt;code&gt;SHIFT&lt;/code&gt;  +  &lt;code&gt;l&lt;/code&gt; : move to the window on the right.&lt;/li&gt;
&lt;li&gt;&lt;code&gt;ALT&lt;/code&gt;  +  &lt;code&gt;SHIFT&lt;/code&gt;  +  &lt;code&gt;j&lt;/code&gt; : move to the window below.&lt;/li&gt;
&lt;li&gt;&lt;code&gt;ALT&lt;/code&gt;  +  &lt;code&gt;SHIFT&lt;/code&gt;  +  &lt;code&gt;k&lt;/code&gt; : move to the window above.&lt;/li&gt;
&lt;li&gt;&lt;code&gt;ALT&lt;/code&gt;  +  &lt;code&gt;SHIFT&lt;/code&gt;  +  &lt;code&gt;n&lt;/code&gt; : move to the previous window.&lt;/li&gt;
&lt;li&gt;&lt;code&gt;ALT&lt;/code&gt;  +  &lt;code&gt;-&lt;/code&gt; : paste register 0 to terminal.&lt;/li&gt;
&lt;li&gt;&lt;code&gt;ALT&lt;/code&gt;  +  &lt;code&gt;q&lt;/code&gt; : switch to terminal normal mode.&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;Inside the terminal:&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;drop abc.txt
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;tell vim to open  &lt;code&gt;abc.txt&lt;/code&gt;&lt;/p&gt;
&lt;h2 id=&#34;vim-translator插件&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#vim-translator插件&#34;&gt;#&lt;/a&gt; vim-translator 插件&lt;/h2&gt;
&lt;h4 id=&#34;translate&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#translate&#34;&gt;#&lt;/a&gt;  &lt;code&gt;Translate&lt;/code&gt;&lt;/h4&gt;
&lt;pre&gt;&lt;code class=&#34;language-sh&#34;&gt;:Translate[!] [--engines=ENGINES] [--target_lang=TARGET_LANG] [--source_lang=SOURCE_LANG] [your text]
&lt;/code&gt;&lt;/pre&gt;
&lt;pre&gt;&lt;code class=&#34;language-sh&#34;&gt;:Translate                                  &amp;quot; translate the word under the cursor
:Translate --engines=google,youdao are you ok &amp;quot; translate text `are you ok` using google and youdao engines
:2Translate ...                             &amp;quot; translate line 2
:1,3Translate ...                           &amp;quot; translate line 1 to line 3
:&#39;&amp;lt;,&#39;&amp;gt;Translate ...                         &amp;quot; translate selected lines
&lt;/code&gt;&lt;/pre&gt;
&lt;h4 id=&#34;translatew&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#translatew&#34;&gt;#&lt;/a&gt;  &lt;code&gt;TranslateW&lt;/code&gt;&lt;/h4&gt;
&lt;pre&gt;&lt;code&gt;:TranslateW[!] [--engines=ENGINES] [--target_lang=TARGET_LANG] [--source_lang=SOURCE_LANG] [your text]
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;Like  &lt;code&gt;:Translate...&lt;/code&gt; , but display the translation in a window&lt;/p&gt;
&lt;h4 id=&#34;translater&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#translater&#34;&gt;#&lt;/a&gt;  &lt;code&gt;TranslateR&lt;/code&gt;&lt;/h4&gt;
&lt;pre&gt;&lt;code&gt;:TranslateR[!] [--engines=ENGINES] [--target_lang=TARGET_LANG] [--source_lang=SOURCE_LANG] [your text]
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;Like  &lt;code&gt;:Translate...&lt;/code&gt; , but replace the current text with the translation&lt;/p&gt;
&lt;h4 id=&#34;translatex&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#translatex&#34;&gt;#&lt;/a&gt;  &lt;code&gt;TranslateX&lt;/code&gt;&lt;/h4&gt;
&lt;pre&gt;&lt;code&gt;:TranslateX[!] [--engines=ENGINES] [--target_lang=TARGET_LANG] [--source_lang=SOURCE_LANG] [your text]
&lt;/code&gt;&lt;/pre&gt;
&lt;h4 id=&#34;translateh&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#translateh&#34;&gt;#&lt;/a&gt;  &lt;code&gt;TranslateH&lt;/code&gt;&lt;/h4&gt;
&lt;pre&gt;&lt;code&gt;:TranslateH
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;Export the translation history&lt;/p&gt;
&lt;h4 id=&#34;translatel&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#translatel&#34;&gt;#&lt;/a&gt;  &lt;code&gt;TranslateL&lt;/code&gt;&lt;/h4&gt;
&lt;pre&gt;&lt;code&gt;:TranslateL
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;Display log messageranslate the text in the clipboard&lt;/p&gt;
&lt;h3 id=&#34;highlight&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#highlight&#34;&gt;#&lt;/a&gt; Highlight&lt;/h3&gt;
&lt;p&gt;Here are the default highlight links. To customize, use  &lt;code&gt;hi&lt;/code&gt;  or  &lt;code&gt;hi link&lt;/code&gt;&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;&amp;quot; Text highlight of translator window
hi def link TranslatorQuery             Identifier
hi def link TranslatorDelimiter         Special
hi def link TranslatorExplain           Statement

&amp;quot; Background of translator window border
hi def link Translator                  Normal
hi def link TranslatorBorder            NormalFloat
&lt;/code&gt;&lt;/pre&gt;
&lt;h2 id=&#34;vim-bookmarks插件&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#vim-bookmarks插件&#34;&gt;#&lt;/a&gt; vim-bookmarks 插件&lt;/h2&gt;
&lt;table&gt;
&lt;thead&gt;
&lt;tr&gt;
&lt;th&gt;Action&lt;/th&gt;
&lt;th&gt;Shortcut&lt;/th&gt;
&lt;th&gt;Command&lt;/th&gt;
&lt;/tr&gt;
&lt;/thead&gt;
&lt;tbody&gt;
&lt;tr&gt;
&lt;td&gt;Add/remove bookmark at current line&lt;/td&gt;
&lt;td&gt;&lt;code&gt;mm&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;&lt;code&gt;:BookmarkToggle&lt;/code&gt;&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;Add/edit/remove annotation at current line&lt;/td&gt;
&lt;td&gt;&lt;code&gt;mi&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;&lt;code&gt;:BookmarkAnnotate &amp;lt;TEXT&amp;gt;&lt;/code&gt;&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;Jump to next bookmark in buffer&lt;/td&gt;
&lt;td&gt;&lt;code&gt;mn&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;&lt;code&gt;:BookmarkNext&lt;/code&gt;&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;Jump to previous bookmark in buffer&lt;/td&gt;
&lt;td&gt;&lt;code&gt;mp&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;&lt;code&gt;:BookmarkPrev&lt;/code&gt;&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;Show all bookmarks (toggle)&lt;/td&gt;
&lt;td&gt;&lt;code&gt;ma&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;&lt;code&gt;:BookmarkShowAll&lt;/code&gt;&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;Clear bookmarks in current buffer only&lt;/td&gt;
&lt;td&gt;&lt;code&gt;mc&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;&lt;code&gt;:BookmarkClear&lt;/code&gt;&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;Clear bookmarks in all buffers&lt;/td&gt;
&lt;td&gt;&lt;code&gt;mx&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;&lt;code&gt;:BookmarkClearAll&lt;/code&gt;&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;Move up bookmark at current line&lt;/td&gt;
&lt;td&gt;&lt;code&gt;[count]mkk&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;&lt;code&gt;:BookmarkMoveUp [&amp;lt;COUNT&amp;gt;]&lt;/code&gt;&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;Move down bookmark at current line&lt;/td&gt;
&lt;td&gt;&lt;code&gt;[count]mjj&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;&lt;code&gt;:BookmarkMoveDown [&amp;lt;COUNT&amp;gt;]&lt;/code&gt;&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;Move bookmark at current line to another line&lt;/td&gt;
&lt;td&gt;&lt;code&gt;[count]mg&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;&lt;code&gt;:BookmarkMoveToLine &amp;lt;LINE&amp;gt;&lt;/code&gt;&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;Save all bookmarks to a file&lt;/td&gt;
&lt;td&gt;&lt;/td&gt;
&lt;td&gt;&lt;code&gt;:BookmarkSave &amp;lt;FILE_PATH&amp;gt;&lt;/code&gt;&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;Load bookmarks from a file&lt;/td&gt;
&lt;td&gt;&lt;/td&gt;
&lt;td&gt;&lt;code&gt;:BookmarkLoad &amp;lt;FILE_PATH&amp;gt;&lt;/code&gt;&lt;/td&gt;
&lt;/tr&gt;
&lt;/tbody&gt;
&lt;/table&gt;
&lt;script type=&#34;text&amp;#x2F;javascript&#34; src=&#34;https://cdn.jsdelivr.net/npm/kity@2.0.4/dist/kity.min.js&#34;&gt;&lt;/script&gt;&lt;script type=&#34;text&amp;#x2F;javascript&#34; src=&#34;https://cdn.jsdelivr.net/npm/kityminder-core@1.4.50/dist/kityminder.core.min.js&#34;&gt;&lt;/script&gt;&lt;script defer=&#34;true&#34; type=&#34;text&amp;#x2F;javascript&#34; src=&#34;https://cdn.jsdelivr.net/npm/hexo-simple-mindmap@0.7.0/dist/mindmap.min.js&#34;&gt;&lt;/script&gt;&lt;link rel=&#34;stylesheet&#34; type=&#34;text&amp;#x2F;css&#34; href=&#34;https://cdn.jsdelivr.net/npm/hexo-simple-mindmap@0.7.0/dist/mindmap.min.css&#34;&gt;

 &lt;h1 id=&#34;vim-快捷键_vim快捷键映射mapping&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#vim-快捷键_vim快捷键映射mapping&#34;&gt;#&lt;/a&gt; vim 快捷键_Vim 快捷键映射 mapping&lt;/h1&gt;
&lt;p&gt;&lt;img data-src=&#34;https://img-blog.csdnimg.cn/img_convert/a09eceab8df67eea52ead4df1ec12d1a.png&#34; alt=&#34;a09eceab8df67eea52ead4df1ec12d1a.png&#34; /&gt;&lt;/p&gt;
&lt;p&gt;使用一段时间&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly9zby5jc2RuLm5ldC9zby9zZWFyY2g/cT12aW0mYW1wO3NwbT0xMDAxLjIxMDEuMzAwMS43MDIw&#34;&gt; vim&lt;/span&gt; 后，多多少少会开始接触 vim 的快捷键映射（mapping），快捷键映射（mapping）能够帮助我们大幅度提高使用 vim 编辑文档的效率。希望通过这篇文章，大家可以比较清晰的理解 vim 快捷键映射（mapping）的基本工作机制，并能够定制自己的快捷键。&lt;/p&gt;
&lt;p&gt;先看一个简单的例子。我们可以将下面的脚本输入到 vim&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly9zby5jc2RuLm5ldC9zby9zZWFyY2g/cT0lRTUlOTElQkQlRTQlQkIlQTQlRTglQTElOEMmYW1wO3NwbT0xMDAxLjIxMDEuMzAwMS43MDIw&#34;&gt; 命令行&lt;/span&gt;（command line）中，或写入 &lt;code&gt;~/.vimrc&lt;/code&gt;  中（永久保存映射关系）。&lt;/p&gt;
&lt;figure class=&#34;highlight python&#34;&gt;&lt;figcaption data-lang=&#34;python&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token builtin&#34;&gt;map&lt;/span&gt; &lt;span class=&#34;token operator&#34;&gt;&amp;lt;&lt;/span&gt;F2&lt;span class=&#34;token operator&#34;&gt;&gt;&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;:&lt;/span&gt;echo &lt;span class=&#34;token string&#34;&gt;&#39;Current time is &#39;&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt; strftime&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token string&#34;&gt;&#39;%c&#39;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;&amp;lt;&lt;/span&gt;CR&lt;span class=&#34;token operator&#34;&gt;&gt;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;p&gt;通过执行以上的脚本之后，在 vim 中，每次在键盘上按 &lt;code&gt;F2&lt;/code&gt;  时，就相当于通过键盘敲击接下来的内容 &lt;code&gt;:echo &#39;Current time is &#39; . strftime(&#39;%c&#39;)&amp;lt;CR&amp;gt;&lt;/code&gt; 。&lt;/p&gt;
&lt;p&gt;大家可以手动试一下，查看效果，敲击冒号 &lt;code&gt;:&lt;/code&gt;  进入命令行（command line）， &lt;code&gt;&amp;lt;CR&amp;gt;&lt;/code&gt;  表示回车键。&lt;/p&gt;
&lt;h2 id=&#34;快捷键映射mapping命令结构&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#快捷键映射mapping命令结构&#34;&gt;#&lt;/a&gt; 快捷键映射（mapping）命令结构&lt;/h2&gt;
&lt;p&gt;我们可以查看 vim 关于快捷键映射（mapping）自带的帮助文档， &lt;code&gt;:help map.txt&lt;/code&gt; 。不过会有一些枯燥难懂。&lt;/p&gt;
&lt;p&gt;vim 快捷键映射（mapping）命令结构如下：&lt;/p&gt;
&lt;figure class=&#34;highlight python&#34;&gt;&lt;figcaption data-lang=&#34;python&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token builtin&#34;&gt;map&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;-&lt;/span&gt;commands &lt;span class=&#34;token builtin&#34;&gt;map&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;-&lt;/span&gt;arguments &lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;lhs&lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;rhs&lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;h3 id=&#34;map-commands&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#map-commands&#34;&gt;#&lt;/a&gt; map-commands&lt;/h3&gt;
&lt;p&gt;第一个部分 &lt;code&gt;map-commands&lt;/code&gt;  定义了&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;快捷键映射作用于哪种工作模式（mode）&lt;/li&gt;
&lt;li&gt;快捷键映射是否可以递归（recursive）&lt;/li&gt;
&lt;li&gt;是执行添加映射，还是删除映射，还是获取映射列表&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;例如 &lt;code&gt;nnoremap&lt;/code&gt;&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;&lt;code&gt;n-&lt;/code&gt;  normal mode 一般模式&lt;/li&gt;
&lt;li&gt;&lt;code&gt;-nore-&lt;/code&gt;  no recursive 不递归&lt;/li&gt;
&lt;li&gt;&lt;code&gt;-map&lt;/code&gt;  添加映射&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;更多可以查看帮助文档 &lt;code&gt;:help map-commands&lt;/code&gt;&lt;/p&gt;
&lt;h3 id=&#34;map-arguments&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#map-arguments&#34;&gt;#&lt;/a&gt; map-arguments&lt;/h3&gt;
&lt;p&gt;第二部分 &lt;code&gt;map-arguments&lt;/code&gt;  特殊参数，紧接着 &lt;code&gt;map-command&lt;/code&gt; ，可选。&lt;/p&gt;
&lt;p&gt;例如 &lt;code&gt;&amp;lt;buffer&amp;gt;&lt;/code&gt; , 表示当前映射仅作用于当前 buffer，添加该参数后的完整映射（map）命令如下&lt;/p&gt;
&lt;figure class=&#34;highlight xml&#34;&gt;&lt;figcaption data-lang=&#34;XML&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;map &lt;span class=&#34;token tag&#34;&gt;&lt;span class=&#34;token tag&#34;&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;lt;&lt;/span&gt;buffer&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;&gt;&lt;/span&gt;&lt;/span&gt; &lt;span class=&#34;token tag&#34;&gt;&lt;span class=&#34;token tag&#34;&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;lt;&lt;/span&gt;F2&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;&gt;&lt;/span&gt;&lt;/span&gt; :echo &#39;Current time is &#39; . strftime(&#39;%c&#39;)&lt;span class=&#34;token tag&#34;&gt;&lt;span class=&#34;token tag&#34;&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;lt;&lt;/span&gt;CR&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;&gt;&lt;/span&gt;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;h3 id=&#34;lhs-left-hand-side&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#lhs-left-hand-side&#34;&gt;#&lt;/a&gt; {lhs} left-hand side&lt;/h3&gt;
&lt;p&gt;第三部分 &lt;code&gt;&amp;#123;lhs&amp;#125;&lt;/code&gt;  表示快捷键，希望使用的按键。可以是单个按键也可以是多个。例如上面的 &lt;code&gt;&amp;lt;F2&amp;gt;&lt;/code&gt; 。&lt;/p&gt;
&lt;h3 id=&#34;rhs-right-hand-side&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#rhs-right-hand-side&#34;&gt;#&lt;/a&gt; {rhs} right-hand side&lt;/h3&gt;
&lt;p&gt;第四部分 &lt;code&gt;&amp;#123;rhs&amp;#125;&lt;/code&gt;  表示当快捷键 &lt;code&gt;&amp;#123;lhs&amp;#125;&lt;/code&gt;  触发之后将被执行的内容：&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;可以是一个活多个键盘按键&lt;/li&gt;
&lt;li&gt;vim 内置的命名&lt;/li&gt;
&lt;li&gt;也可以是用 vimscript 编写的方法&lt;/li&gt;
&lt;/ul&gt;
&lt;h3 id=&#34;快捷键映射命令综合小结&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#快捷键映射命令综合小结&#34;&gt;#&lt;/a&gt; 快捷键映射命令综合小结&lt;/h3&gt;
&lt;p&gt;让我们先通过下面的例子做一个小结&lt;/p&gt;
&lt;figure class=&#34;highlight ruby&#34;&gt;&lt;figcaption data-lang=&#34;ruby&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;nnoremap &lt;span class=&#34;token operator&#34;&gt;&amp;lt;&lt;/span&gt;slient&lt;span class=&#34;token operator&#34;&gt;&gt;&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;&amp;lt;&lt;/span&gt;space&lt;span class=&#34;token operator&#34;&gt;&gt;&lt;/span&gt; &lt;span class=&#34;token symbol&#34;&gt;:nohlsearch&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;&amp;lt;&lt;/span&gt;&lt;span class=&#34;token constant&#34;&gt;CR&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;&gt;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;p&gt;每当我们在一般模式（normal mode）中，按下 &lt;code&gt;,&amp;lt;space&amp;gt;&lt;/code&gt; (逗号和空格），等同于敲击冒号 &lt;code&gt;:&lt;/code&gt;  进入如命令行，然后输入命令 &lt;code&gt;nohlsearch&lt;/code&gt;  并按下回车键。&lt;/p&gt;
&lt;p&gt;其中 &lt;code&gt;&amp;lt;slient&amp;gt;&lt;/code&gt;  告诉 vim 不要把输入到命令行的内容显示出来。&lt;/p&gt;
&lt;p&gt;&lt;code&gt;-nore-&lt;/code&gt;  表示，如果 &lt;code&gt;,&amp;lt;space&amp;gt;&lt;/code&gt;  出现在其它快捷键命令的 &lt;code&gt;&amp;#123;rhs&amp;#125; right-hand side&lt;/code&gt;  部分，不会再被当做快捷键递归触发。&lt;/p&gt;
&lt;h2 id=&#34;快捷键映射命令map-commands-map-commands&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#快捷键映射命令map-commands-map-commands&#34;&gt;#&lt;/a&gt; 快捷键映射命令 Map Commands - :map-commands&lt;/h2&gt;
&lt;p&gt;前面已经提过了，快捷键映射命令的三个职责&lt;/p&gt;
&lt;ol&gt;
&lt;li&gt;作用于哪个工作模式（mode）&lt;/li&gt;
&lt;li&gt;是否可以递归（recursive）&lt;/li&gt;
&lt;li&gt;执行添加，删除，还是获取列表操作&lt;/li&gt;
&lt;/ol&gt;
&lt;p&gt;一般可以通过第一个字母判断对对应的工作模式（mode），帮助文档中有更详细的资料&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-shel&#34;&gt;:help map-overview
     COMMANDS                    MODES

:map   :noremap  :unmap     Normal, Visual, Select, Operator-pending
:nmap  :nnoremap :nunmap    Normal
:vmap  :vnoremap :vunmap    Visual and Select
:smap  :snoremap :sunmap    Select
:xmap  :xnoremap :xunmap    Visual
:omap  :onoremap :ounmap    Operator-pending
:map!  :noremap! :unmap!    Insert and Command-line
:imap  :inoremap :iunmap    Insert
:lmap  :lnoremap :lunmap    Insert, Command-line, Lang-Arg
:cmap  :cnoremap :cunmap    Command-line
:tmap  :tnoremap :tunmap    Terminal-Job
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;命令中是否包含 &lt;code&gt;-nore-&lt;/code&gt;  来判断是否接受递归，如上面表格 &lt;code&gt;COMMANDS&lt;/code&gt;  中第二列。&lt;/p&gt;
&lt;p&gt;当存在 &lt;code&gt;&amp;#123;lhs&amp;#125;&lt;/code&gt;  和 &lt;code&gt;&amp;#123;rhs&amp;#125;&lt;/code&gt;  表示添加映射（mapping）关系 ，例如&lt;/p&gt;
&lt;figure class=&#34;highlight cpp&#34;&gt;&lt;figcaption data-lang=&#34;C++&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token operator&#34;&gt;:&lt;/span&gt;map &lt;span class=&#34;token operator&#34;&gt;&amp;lt;&lt;/span&gt;F3&lt;span class=&#34;token operator&#34;&gt;&gt;&lt;/span&gt;  o#include&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;p&gt;包含 &lt;code&gt;-un-&lt;/code&gt;  时表示删除，如上面表格 &lt;code&gt;COMMANDS&lt;/code&gt;  中第三列，例如&lt;/p&gt;
&lt;figure class=&#34;highlight xml&#34;&gt;&lt;figcaption data-lang=&#34;XML&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;:unmap &lt;span class=&#34;token tag&#34;&gt;&lt;span class=&#34;token tag&#34;&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;lt;&lt;/span&gt;F3&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;&gt;&lt;/span&gt;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;h2 id=&#34;特殊参数-special-arguments-map-argments&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#特殊参数-special-arguments-map-argments&#34;&gt;#&lt;/a&gt; 特殊参数 Special Arguments - :map-argments&lt;/h2&gt;
&lt;p&gt;特殊参数包括 &lt;code&gt;&amp;lt;buffer&amp;gt;&lt;/code&gt; ,  &lt;code&gt;&amp;lt;nowait&amp;gt;&lt;/code&gt; ,  &lt;code&gt;&amp;lt;silent&amp;gt;&lt;/code&gt; ,  &lt;code&gt;&amp;lt;special&amp;gt;&lt;/code&gt; ,  &lt;code&gt;&amp;lt;script&amp;gt;&lt;/code&gt; ,  &lt;code&gt;&amp;lt;expr&amp;gt;&lt;/code&gt;  和 &lt;code&gt;&amp;lt;unique&amp;gt;&lt;/code&gt; ，它们可以以任意次序放置。&lt;/p&gt;
&lt;h3 id=&#34;buffer&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#buffer&#34;&gt;#&lt;/a&gt;  &lt;code&gt;&amp;lt;buffer&amp;gt;&lt;/code&gt;&lt;/h3&gt;
&lt;p&gt;&lt;code&gt;&amp;lt;bufefr&amp;gt;&lt;/code&gt;  表示快捷键映射命令只作用于当前 buffer，也可以说时本地 buffer 映射。&lt;/p&gt;
&lt;h3 id=&#34;nowait&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#nowait&#34;&gt;#&lt;/a&gt;  &lt;code&gt;&amp;lt;nowait&amp;gt;&lt;/code&gt;&lt;/h3&gt;
&lt;p&gt;&lt;code&gt;&amp;lt;nowait&amp;gt;&lt;/code&gt;  表示无需等待。比方说一个本地 buffer 映射是 &lt;code&gt;,&lt;/code&gt;  和一个全局映射是 &lt;code&gt;,a&lt;/code&gt; ，如下&lt;/p&gt;
&lt;figure class=&#34;highlight xml&#34;&gt;&lt;figcaption data-lang=&#34;XML&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;map &lt;span class=&#34;token tag&#34;&gt;&lt;span class=&#34;token tag&#34;&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;lt;&lt;/span&gt;buffer&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;&gt;&lt;/span&gt;&lt;/span&gt; , :echo &#39;local buffer mapping&#39;&lt;span class=&#34;token tag&#34;&gt;&lt;span class=&#34;token tag&#34;&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;lt;&lt;/span&gt;CR&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;&gt;&lt;/span&gt;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;2&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;3&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;4&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;5&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;map ,a aGlobal Mapping&lt;span class=&#34;token tag&#34;&gt;&lt;span class=&#34;token tag&#34;&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;lt;&lt;/span&gt;ESC&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;&gt;&lt;/span&gt;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;p&gt;这个时候当我们按下逗号 &lt;code&gt;,&lt;/code&gt;  键，vim 需要等一段时间或者按下第二个键，才能确定触发哪个快捷键。&lt;/p&gt;
&lt;p&gt;或者我们可以使用 &lt;code&gt;&amp;lt;nowait&amp;gt;&lt;/code&gt;  参数告诉 vim 无需等待， 直接触发已经匹配好的快捷键。当然那一个长一点的快捷键 &lt;code&gt;,a&lt;/code&gt;  在当前 buffer 就无法再使用了。&lt;/p&gt;
&lt;figure class=&#34;highlight xml&#34;&gt;&lt;figcaption data-lang=&#34;XML&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;map &lt;span class=&#34;token tag&#34;&gt;&lt;span class=&#34;token tag&#34;&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;lt;&lt;/span&gt;buffer&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;token tag&#34;&gt;&lt;span class=&#34;token tag&#34;&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;lt;&lt;/span&gt;nowait&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;&gt;&lt;/span&gt;&lt;/span&gt; , :echo &#39;local buffer mapping&#39;&lt;span class=&#34;token tag&#34;&gt;&lt;span class=&#34;token tag&#34;&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;lt;&lt;/span&gt;CR&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;&gt;&lt;/span&gt;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;h3 id=&#34;silent&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#silent&#34;&gt;#&lt;/a&gt;  &lt;code&gt;&amp;lt;silent&amp;gt;&lt;/code&gt;&lt;/h3&gt;
&lt;p&gt;&lt;code&gt;&amp;lt;silent&amp;gt;&lt;/code&gt;  表示不在命令行（command line）中显示任何信息&lt;/p&gt;
&lt;h3 id=&#34;special&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#special&#34;&gt;#&lt;/a&gt;  &lt;code&gt;&amp;lt;special&amp;gt;&lt;/code&gt;&lt;/h3&gt;
&lt;p&gt;没看明白，原文如下&lt;/p&gt;
&lt;blockquote&gt;
&lt;pre&gt;&lt;code&gt;&amp;lt;special&amp;gt;` Define a mapping with &amp;lt;&amp;gt; notation for special keys, even though the &amp;quot;&amp;lt;&amp;quot; flag may appear in &#39;cpoptions&#39;. This is useful if the side effect of setting &#39;cpoptions&#39; is not desired. Example: `:map &amp;lt;special&amp;gt; &amp;lt;F12&amp;gt; /Header&amp;lt;CR&amp;gt;
&lt;/code&gt;&lt;/pre&gt;
&lt;/blockquote&gt;
&lt;h3 id=&#34;script&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#script&#34;&gt;#&lt;/a&gt;  &lt;code&gt;&amp;lt;script&amp;gt;&lt;/code&gt;&lt;/h3&gt;
&lt;p&gt;&amp;lt;script&amp;gt; 表示仅递归脚本（script）或插件（plugin）内部以 &amp;lt; SID &amp;gt; 打头的映射。&lt;/p&gt;
&lt;p&gt;例如在 &lt;code&gt;~/.vimrc&lt;/code&gt;  中有如下代码，当我们按下 &lt;code&gt;,dt&lt;/code&gt; ，触发执行 &lt;code&gt;&amp;lt;SID&amp;gt;(FindTopic)dd&lt;/code&gt; ，&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;其中  &lt;code&gt;&amp;lt;SID&amp;gt;(FindTopic)&lt;/code&gt;  会被递归到 &lt;code&gt;/Topic&amp;lt;CR&amp;gt;&lt;/code&gt; ，即，搜索 &lt;code&gt;Topic&lt;/code&gt;&lt;/li&gt;
&lt;li&gt;但 &lt;code&gt;dd&lt;/code&gt;  不做递归，就是按两个 &lt;code&gt;d&lt;/code&gt; ，即删除当前行&lt;/li&gt;
&lt;/ul&gt;
&lt;figure class=&#34;highlight xml&#34;&gt;&lt;figcaption data-lang=&#34;XML&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;noremap &lt;span class=&#34;token tag&#34;&gt;&lt;span class=&#34;token tag&#34;&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;lt;&lt;/span&gt;SID&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;&gt;&lt;/span&gt;&lt;/span&gt;(FindTopic) /Topic&lt;span class=&#34;token tag&#34;&gt;&lt;span class=&#34;token tag&#34;&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;lt;&lt;/span&gt;CR&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;&gt;&lt;/span&gt;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;2&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;noremap dd :echo &#39;dd&#39;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;3&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;noremap &lt;span class=&#34;token tag&#34;&gt;&lt;span class=&#34;token tag&#34;&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;lt;&lt;/span&gt;script&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;&gt;&lt;/span&gt;&lt;/span&gt; ,dt &lt;span class=&#34;token tag&#34;&gt;&lt;span class=&#34;token tag&#34;&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;lt;&lt;/span&gt;SID&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;&gt;&lt;/span&gt;&lt;/span&gt;(FindTopic)dd&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;h3 id=&#34;expr&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#expr&#34;&gt;#&lt;/a&gt;  &lt;code&gt;&amp;lt;expr&amp;gt;&lt;/code&gt;&lt;/h3&gt;
&lt;p&gt;&lt;code&gt;&amp;lt;expr&amp;gt;&lt;/code&gt;  表示 &lt;code&gt;&amp;#123;rhs&amp;#125;&lt;/code&gt;  是表达式，表达式的返回值，作为最后映射的捷键序列。&lt;/p&gt;
&lt;p&gt;例如在 &lt;code&gt;~/.vimrc&lt;/code&gt;  中，当按下 &lt;code&gt;,a&lt;/code&gt;  是就相当于按下 &lt;code&gt;abcdef&lt;/code&gt; .&lt;/p&gt;
&lt;figure class=&#34;highlight swift&#34;&gt;&lt;figcaption data-lang=&#34;swift&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;inoremap &lt;span class=&#34;token operator&#34;&gt;&amp;lt;&lt;/span&gt;expr&lt;span class=&#34;token operator&#34;&gt;&gt;&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;a &lt;span class=&#34;token class-name&#34;&gt;InsertSth&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;2&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;func&lt;/span&gt; &lt;span class=&#34;token function-definition function&#34;&gt;InsertSth&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;3&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;  &lt;span class=&#34;token keyword&#34;&gt;return&lt;/span&gt; &lt;span class=&#34;token string-literal&#34;&gt;&lt;span class=&#34;token string&#34;&gt;&#34;abcdef&#34;&lt;/span&gt;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;4&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;endfunc&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;h3 id=&#34;unique&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#unique&#34;&gt;#&lt;/a&gt;  &lt;code&gt;&amp;lt;unique&amp;gt;&lt;/code&gt;&lt;/h3&gt;
&lt;p&gt;&lt;code&gt;&amp;lt;unique&amp;gt;&lt;/code&gt;  用于避免已经存在的快捷键被覆盖&lt;/p&gt;
&lt;h2 id=&#34;小结&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#小结&#34;&gt;#&lt;/a&gt; 小结&lt;/h2&gt;
&lt;p&gt;希望以上的内容对大家有所帮助，可以搭建自己的快捷键映射。&lt;/p&gt;
&lt;script type=&#34;text&amp;#x2F;javascript&#34; src=&#34;https://cdn.jsdelivr.net/npm/kity@2.0.4/dist/kity.min.js&#34;&gt;&lt;/script&gt;&lt;script type=&#34;text&amp;#x2F;javascript&#34; src=&#34;https://cdn.jsdelivr.net/npm/kityminder-core@1.4.50/dist/kityminder.core.min.js&#34;&gt;&lt;/script&gt;&lt;script defer=&#34;true&#34; type=&#34;text&amp;#x2F;javascript&#34; src=&#34;https://cdn.jsdelivr.net/npm/hexo-simple-mindmap@0.7.0/dist/mindmap.min.js&#34;&gt;&lt;/script&gt;&lt;link rel=&#34;stylesheet&#34; type=&#34;text&amp;#x2F;css&#34; href=&#34;https://cdn.jsdelivr.net/npm/hexo-simple-mindmap@0.7.0/dist/mindmap.min.css&#34;&gt;

 &lt;h1 id=&#34;命令模式可以使用的按键说明&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#命令模式可以使用的按键说明&#34;&gt;#&lt;/a&gt; 命令模式可以使用的按键说明&lt;/h1&gt;
&lt;h2 id=&#34;光标控制按键&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#光标控制按键&#34;&gt;#&lt;/a&gt; 光标控制按键&lt;/h2&gt;
&lt;table&gt;
&lt;thead&gt;
&lt;tr&gt;
&lt;th style=&#34;text-align:center&#34;&gt;按键&lt;/th&gt;
&lt;th style=&#34;text-align:center&#34;&gt;意义&lt;/th&gt;
&lt;/tr&gt;
&lt;/thead&gt;
&lt;tbody&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;h&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;光标向左移动一个字符&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;l&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;光标向右移动一个字符&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;j&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;光标向下移动一行&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;k&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;光标向上移动行&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;ctrl+b&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;向上翻一页&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;ctrl+f&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;向下翻一页&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;ctrl+u&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;向上翻半页&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;ctrl+d&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;向下翻半页&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;[n]+space&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;在光标向右移动 n 个字符&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;[n]+j&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;向下移动 n 行&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;[n]+k&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;向上移动 n 行&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;0&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;移动到当前行的行首&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;$&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;移动到当前行的行尾&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;shift+h 或 H&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;移动到当前屏幕顶行行首&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;shift+m 或 M&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;移动到当前屏幕中间行行首&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;shift+l 或 L&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;移动到当前屏幕底行行首&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;shift+g 或 G&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;移动到文档的最后一行&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;[n]+G&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;移动到这个文件的第 n 行&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;gg&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;移动文档的首行，相当于 1G&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;[n]&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;光标向下移动 n 行&lt;/td&gt;
&lt;/tr&gt;
&lt;/tbody&gt;
&lt;/table&gt;
&lt;ul&gt;
&lt;li&gt;&lt;code&gt;hjkl&lt;/code&gt;  左右下上&lt;/li&gt;
&lt;li&gt;&lt;code&gt;ctrl&lt;/code&gt; + &lt;code&gt;bfud&lt;/code&gt;  上下一页上下半页&lt;/li&gt;
&lt;li&gt;&lt;code&gt;HMLG&lt;/code&gt;  上中下低&lt;/li&gt;
&lt;/ul&gt;
&lt;h2 id=&#34;搜索与替换&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#搜索与替换&#34;&gt;#&lt;/a&gt; 搜索与替换&lt;/h2&gt;
&lt;table&gt;
&lt;thead&gt;
&lt;tr&gt;
&lt;th style=&#34;text-align:center&#34;&gt;命令&lt;/th&gt;
&lt;th style=&#34;text-align:center&#34;&gt;意义&lt;/th&gt;
&lt;/tr&gt;
&lt;/thead&gt;
&lt;tbody&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;/abc&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;在光标以下的文本中查找一个名为 abc 的字符串&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;?abc&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;在光标以上的文本中查找一个名为 abc 的字符串&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;n&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;重复前一个查找动作&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;N&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;与 n 相反，重复后一个查找动作&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;:[n1],[n2]s/abc1/abc2/g&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;在 n1 与 n2 行之间查找 abc1 并替换为 abc2&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;:1,$s/abc1/abc2/g&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;从第一行到最后一行查找 abc1 并替换为 abc2&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;:1,$s/abc1/abc2/gc&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;从第一行到最后一行查找 abc1 并替换为 abc2, 且在替换前显示提示字符给用户确认&lt;/td&gt;
&lt;/tr&gt;
&lt;/tbody&gt;
&lt;/table&gt;
&lt;h2 id=&#34;删除与复制&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#删除与复制&#34;&gt;#&lt;/a&gt; 删除与复制&lt;/h2&gt;
&lt;table&gt;
&lt;thead&gt;
&lt;tr&gt;
&lt;th style=&#34;text-align:center&#34;&gt;命令&lt;/th&gt;
&lt;th style=&#34;text-align:center&#34;&gt;作用&lt;/th&gt;
&lt;/tr&gt;
&lt;/thead&gt;
&lt;tbody&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;x&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;删除光标后面的一个字符&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;[n]x&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;删除光标后面的 n 个字符&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;dd&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;删除光标所在行&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;[n]dd&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;删除光标一下 n 行，包括光标所在行&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;d1G&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;删除光标所在行到第一行之间的所有行，包括第一行和光标所在行&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;dG&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;删除光标所在行到最后一行之间的所有行，包括光标所在行和最后一行&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;d$&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;删除光标所在到该行的末尾&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;dw&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;删除光标所在的单词&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;dnw&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;删除光标开始改行的 n 个单词&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;d0&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;删除当前位置到行首&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;yy&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;复制光标所在行&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;nyy&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;复制光标以下 n 行，包括光标所在行&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;y1G&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;复制第一行到光标所在行&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;yG&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;复制当前行到最后一行&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;y0&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;复制当前位置到行首&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;y$&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;复制当前位置到行尾&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;yw&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;复制当前位置的单词&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;ynw&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;复制当前位置以后的 n 个单词&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;p,P&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;p 为将复制的内容粘贴到光标的下一行，P 为将复制的内容粘贴到光标的上一行&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;u&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;撤销动作&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;ctrl + r&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;重做上一个动作&lt;/td&gt;
&lt;/tr&gt;
&lt;/tbody&gt;
&lt;/table&gt;
&lt;h2 id=&#34;从命令模式到末行模式&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#从命令模式到末行模式&#34;&gt;#&lt;/a&gt; 从命令模式到末行模式&lt;/h2&gt;
&lt;table&gt;
&lt;thead&gt;
&lt;tr&gt;
&lt;th style=&#34;text-align:center&#34;&gt;命令&lt;/th&gt;
&lt;th style=&#34;text-align:center&#34;&gt;作用&lt;/th&gt;
&lt;/tr&gt;
&lt;/thead&gt;
&lt;tbody&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;:w&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;:w!&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;:q&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;:q!&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;:wq&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;ZZ&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;如果文档没有改动，则不存储离开，否则保存后离开&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;:w [filename]&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;将写好的文档保存到一个文件中，类似与另存&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;:r [filename]&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;将指定文件的内容追加到当前文件中光标所在位置的后面&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;:[n1],[n2] w [filename]&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;将 n1 到 n2 行的内容保存到文件中&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;:! [command]&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;在末行模式下使用 shell 命令&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;:set nu&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;显示行号&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;:set nonu&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;取消行号&lt;/td&gt;
&lt;/tr&gt;
&lt;/tbody&gt;
&lt;/table&gt;
&lt;h2 id=&#34;区块选择&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#区块选择&#34;&gt;#&lt;/a&gt; 区块选择&lt;/h2&gt;
&lt;table&gt;
&lt;thead&gt;
&lt;tr&gt;
&lt;th style=&#34;text-align:center&#34;&gt;命令&lt;/th&gt;
&lt;th style=&#34;text-align:center&#34;&gt;作用&lt;/th&gt;
&lt;/tr&gt;
&lt;/thead&gt;
&lt;tbody&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;v&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;字符选择，选中光标经过的地方&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;V&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;选中光标所经过的行&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;alt+v&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;区块选择&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;y&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;复制所选部分&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;d&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;删除选中的部分&lt;/td&gt;
&lt;/tr&gt;
&lt;/tbody&gt;
&lt;/table&gt;
&lt;h2 id=&#34;多文本编辑&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#多文本编辑&#34;&gt;#&lt;/a&gt; 多文本编辑&lt;/h2&gt;
&lt;table&gt;
&lt;thead&gt;
&lt;tr&gt;
&lt;th style=&#34;text-align:center&#34;&gt;命令&lt;/th&gt;
&lt;th style=&#34;text-align:center&#34;&gt;作用&lt;/th&gt;
&lt;/tr&gt;
&lt;/thead&gt;
&lt;tbody&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;:n&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;编辑下一个文件&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;:N&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;编辑上一个文件&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;:files&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;列出目前这个 vim 开启的所有文件&lt;/td&gt;
&lt;/tr&gt;
&lt;/tbody&gt;
&lt;/table&gt;
&lt;h2 id=&#34;多窗口编辑&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#多窗口编辑&#34;&gt;#&lt;/a&gt; 多窗口编辑&lt;/h2&gt;
&lt;table&gt;
&lt;thead&gt;
&lt;tr&gt;
&lt;th style=&#34;text-align:center&#34;&gt;命令&lt;/th&gt;
&lt;th style=&#34;text-align:center&#34;&gt;作用&lt;/th&gt;
&lt;/tr&gt;
&lt;/thead&gt;
&lt;tbody&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;:sp/:vsp [filename]&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;开启一个新窗口，如果加了 filename, 表示在新窗口编辑指定的文件，否则表示连个窗口为同一文件&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;ctrl+w+j&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;跳到下方窗口&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;ctrl+w+k&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;跳到上方窗口&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;ctrl+w+h&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;跳到左边窗口&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;ctrl+w+l&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;跳到右边窗口&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;ctrl+w+q&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;退出当前窗口&lt;/td&gt;
&lt;/tr&gt;
&lt;/tbody&gt;
&lt;/table&gt;
&lt;h2 id=&#34;quickfix指令&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#quickfix指令&#34;&gt;#&lt;/a&gt;  &lt;code&gt;quickfix&lt;/code&gt;  指令&lt;/h2&gt;
&lt;ol&gt;
&lt;li&gt;&lt;code&gt;:CC&lt;/code&gt;  显示编译错误的详细信息，这些信息显示在状态行里&lt;/li&gt;
&lt;li&gt;&lt;code&gt;:cn&lt;/code&gt;  下一个编译错误&lt;/li&gt;
&lt;li&gt;&lt;code&gt;:cw&lt;/code&gt;  打开 Quickfix 窗口，会在屏幕中打开一个新窗口，里面的内容是一个编译错误列表&lt;/li&gt;
&lt;li&gt;&lt;code&gt;:cl&lt;/code&gt;  列出所欲的编译错误&lt;/li&gt;
&lt;li&gt;&lt;code&gt;:col&lt;/code&gt;  前一个列表&lt;/li&gt;
&lt;li&gt;&lt;code&gt;:cnew&lt;/code&gt;  后一个列表&lt;/li&gt;
&lt;/ol&gt;
&lt;script type=&#34;text&amp;#x2F;javascript&#34; src=&#34;https://cdn.jsdelivr.net/npm/kity@2.0.4/dist/kity.min.js&#34;&gt;&lt;/script&gt;&lt;script type=&#34;text&amp;#x2F;javascript&#34; src=&#34;https://cdn.jsdelivr.net/npm/kityminder-core@1.4.50/dist/kityminder.core.min.js&#34;&gt;&lt;/script&gt;&lt;script defer=&#34;true&#34; type=&#34;text&amp;#x2F;javascript&#34; src=&#34;https://cdn.jsdelivr.net/npm/hexo-simple-mindmap@0.7.0/dist/mindmap.min.js&#34;&gt;&lt;/script&gt;&lt;link rel=&#34;stylesheet&#34; type=&#34;text&amp;#x2F;css&#34; href=&#34;https://cdn.jsdelivr.net/npm/hexo-simple-mindmap@0.7.0/dist/mindmap.min.css&#34;&gt;

 &lt;h2 id=&#34;插件相关&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#插件相关&#34;&gt;#&lt;/a&gt; 插件相关&lt;/h2&gt;
&lt;table&gt;
&lt;thead&gt;
&lt;tr&gt;
&lt;th style=&#34;text-align:center&#34;&gt;快捷键&lt;/th&gt;
&lt;th style=&#34;text-align:center&#34;&gt;说明&lt;/th&gt;
&lt;/tr&gt;
&lt;/thead&gt;
&lt;tbody&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;,&lt;/code&gt;&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;Leader Key&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;&amp;lt;leader&amp;gt;n&lt;/code&gt;&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;打开 / 关闭代码资源管理器&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;&amp;lt;leader&amp;gt;t&lt;/code&gt;&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;打开 / 关闭函数列表&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;&amp;lt;leader&amp;gt;a&lt;/code&gt;&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;.h .cpp 文件切换&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;&amp;lt;leader&amp;gt;u&lt;/code&gt;&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;转到函数声明&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;&amp;lt;leader&amp;gt;U&lt;/code&gt;&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;转到函数实现&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;&amp;lt;leader&amp;gt;u&lt;/code&gt;&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;转到变量声明&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;&amp;lt;leader&amp;gt;o&lt;/code&gt;&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;打开 include 文件&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;&amp;lt;leader&amp;gt;y&lt;/code&gt;&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;拷贝函数声明&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;&amp;lt;leader&amp;gt;p&lt;/code&gt;&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;生成函数实现&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;&amp;lt;leader&amp;gt;w&lt;/code&gt;&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;单词跳转&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;&amp;lt;leader&amp;gt;f&lt;/code&gt;&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;搜索～目录下的文件&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;&amp;lt;leader&amp;gt;F&lt;/code&gt;&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;搜索当前目录下的文本&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;&amp;lt;leader&amp;gt;g&lt;/code&gt;&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;显示 git 仓库提交记录&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;&amp;lt;leader&amp;gt;G&lt;/code&gt;&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;显示当前文件提交记录&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;&amp;lt;leader&amp;gt;gg&lt;/code&gt;&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;显示当前文件在某个 commit 下的完整内容&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;&amp;lt;leader&amp;gt;ff&lt;/code&gt;&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;语法错误自动修复 (FixIt)&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;&amp;lt;c-p&amp;gt;&lt;/code&gt;&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;切换到上一个 buffer&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;&amp;lt;c-n&amp;gt;&lt;/code&gt;&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;切换到下一个 buffer&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;&amp;lt;leader&amp;gt;d&lt;/code&gt;&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;删除当前 buffer&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;&amp;lt;leader&amp;gt;D&lt;/code&gt;&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;删除当前 buffer 外的所有 buffer&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;vim&lt;/code&gt;&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;运行 vim 编辑器时，默认启动开始页面&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;&amp;lt;F5&amp;gt;&lt;/code&gt;&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;显示语法错误提示窗口&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;&amp;lt;F9&amp;gt;&lt;/code&gt;&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;显示上一主题&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;&amp;lt;F10&amp;gt;&lt;/code&gt;&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;显示下一主题&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;&amp;lt;leader&amp;gt;l&lt;/code&gt;&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;按竖线对齐&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;&amp;lt;leader&amp;gt;=&lt;/code&gt;&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;按等号对齐&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;Ya&lt;/code&gt;&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;复制行文本到字母 a&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;Da&lt;/code&gt;&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;剪切行文本到字母 a&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;Ca&lt;/code&gt;&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;改写行文本到字母 a&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;rr&lt;/code&gt;&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;替换文本&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;&amp;lt;leader&amp;gt;r&lt;/code&gt;&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;全局替换，目前只支持单个文件&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;rev&lt;/code&gt;&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;翻转当前光标下的单词或使用 V 模式选择的文本&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;gcc&lt;/code&gt;&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;注释代码&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;gcap&lt;/code&gt;&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;注释段落&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;vif&lt;/code&gt;&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;选中函数内容&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;dif&lt;/code&gt;&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;删除函数内容&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;cif&lt;/code&gt;&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;改写函数内容&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;vaf&lt;/code&gt;&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;选中函数内容（包括函数名 花括号）&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;daf&lt;/code&gt;&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;删除函数内容（包括函数名 花括号）&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;caf&lt;/code&gt;&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;改写函数内容（包括函数名 花括号）&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;fa&lt;/code&gt;&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;查找字母 a，然后再按 f 键查找下一个&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;&amp;lt;leader&amp;gt;e&lt;/code&gt;&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;快速编辑～/.vimrc 文件&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;&amp;lt;leader&amp;gt;s&lt;/code&gt;&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;重新加载～/.vimrc 文件&lt;/td&gt;
&lt;/tr&gt;
&lt;/tbody&gt;
&lt;tbody&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;快捷键&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;说明&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;:-----------------:&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;:---------------------------------:&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;&amp;lt;leader&amp;gt;vp&lt;/code&gt;&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;快速编辑～/.vimrc.custom.plugins 文件&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;&amp;lt;leader&amp;gt;vc&lt;/code&gt;&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;快速编辑～/.vimrc.custom.config 文件&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;&amp;lt;leader&amp;gt;h&lt;/code&gt;&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;打开 vimplus 帮助文档&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;&amp;lt;leader&amp;gt;H&lt;/code&gt;&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;打开当前光标所在单词的 vim 帮助文档&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;&amp;lt;leader&amp;gt;&amp;lt;leader&amp;gt;t&lt;/code&gt;&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;生成 try-catch 代码块&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;&amp;lt;leader&amp;gt;&amp;lt;leader&amp;gt;y&lt;/code&gt;&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;复制当前选中到系统剪切板&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;&amp;lt;leader&amp;gt;&amp;lt;leader&amp;gt;i&lt;/code&gt;&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;安装插件&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;&amp;lt;leader&amp;gt;&amp;lt;leader&amp;gt;u&lt;/code&gt;&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;更新插件&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;&amp;lt;leader&amp;gt;&amp;lt;leader&amp;gt;c&lt;/code&gt;&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;删除插件&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;/td&gt;
&lt;/tr&gt;
&lt;/tbody&gt;
&lt;/table&gt;
&lt;h2 id=&#34;插入模式&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#插入模式&#34;&gt;#&lt;/a&gt; 插入模式&lt;/h2&gt;
&lt;table&gt;
&lt;thead&gt;
&lt;tr&gt;
&lt;th&gt;快捷键&lt;/th&gt;
&lt;th&gt;说明&lt;/th&gt;
&lt;/tr&gt;
&lt;/thead&gt;
&lt;tbody&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;i&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;在光标处进入插入模式&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;I&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;在行首进入插入模式&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;a&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;在光标后进入插入模式&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;A&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;在行尾进入插入模式&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;o&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;在下一行插入新行并进入插入模式&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;O&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;在上一行插入新行并进入插入模式&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;gi&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;进入到上一次插入模式的位置&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;&amp;lt;esc&amp;gt;&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;退出插入模式&lt;/td&gt;
&lt;/tr&gt;
&lt;/tbody&gt;
&lt;/table&gt;
&lt;h2 id=&#34;缓存操作&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#缓存操作&#34;&gt;#&lt;/a&gt; 缓存操作&lt;/h2&gt;
&lt;table&gt;
&lt;thead&gt;
&lt;tr&gt;
&lt;th&gt;快捷键&lt;/th&gt;
&lt;th&gt;说明&lt;/th&gt;
&lt;/tr&gt;
&lt;/thead&gt;
&lt;tbody&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;:e &amp;lt;filename&amp;gt;&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;新建 buffer 打开文件&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;:bp&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;切换到上一个 buffer&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;:bn&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;切换到下一个 buffer&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;:bd&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;删除当前 buffer&lt;/td&gt;
&lt;/tr&gt;
&lt;/tbody&gt;
&lt;/table&gt;
&lt;h2 id=&#34;窗口操作&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#窗口操作&#34;&gt;#&lt;/a&gt; 窗口操作&lt;/h2&gt;
&lt;table&gt;
&lt;thead&gt;
&lt;tr&gt;
&lt;th style=&#34;text-align:center&#34;&gt;快捷键&lt;/th&gt;
&lt;th style=&#34;text-align:center&#34;&gt;说明&lt;/th&gt;
&lt;/tr&gt;
&lt;/thead&gt;
&lt;tbody&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;:sp &amp;lt;filename&amp;gt;&lt;/code&gt;&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;横向切分窗口并打开文件&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;:vsp &amp;lt;filename&amp;gt;&lt;/code&gt;&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;竖向切分窗口并打开文件&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;&amp;lt;c-w&amp;gt;h&lt;/code&gt;&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;跳到左边的窗口&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;&amp;lt;c-w&amp;gt;j&lt;/code&gt;&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;跳到下边的窗口&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;&amp;lt;c-w&amp;gt;k&lt;/code&gt;&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;跳到上边的窗口&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;&amp;lt;c-w&amp;gt;l&lt;/code&gt;&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;跳到右边的窗口&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;&amp;lt;c-w&amp;gt;c&lt;/code&gt;&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;关闭当前窗口&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;&amp;lt;c-w&amp;gt;o&lt;/code&gt;&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;关闭其他窗口&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;:only&lt;/code&gt;&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;关闭其他窗口&lt;/td&gt;
&lt;/tr&gt;
&lt;/tbody&gt;
&lt;/table&gt;
&lt;h2 id=&#34;光标移动&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#光标移动&#34;&gt;#&lt;/a&gt; 光标移动&lt;/h2&gt;
&lt;table&gt;
&lt;thead&gt;
&lt;tr&gt;
&lt;th style=&#34;text-align:center&#34;&gt;快捷键&lt;/th&gt;
&lt;th style=&#34;text-align:center&#34;&gt;说明&lt;/th&gt;
&lt;/tr&gt;
&lt;/thead&gt;
&lt;tbody&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;h&lt;/code&gt;&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;上下左右移动&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;j&lt;/code&gt;&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;上下左右移动&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;k&lt;/code&gt;&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;上下左右移动&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;l&lt;/code&gt;&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;上下左右移动&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;0&lt;/code&gt;&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;光标移动到行首&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;^&lt;/code&gt;&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;跳到从行首开始第一个非空白字符&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;$&lt;/code&gt;&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;光标移动到行尾&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;&amp;lt;c-o&amp;gt;&lt;/code&gt;&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;跳到上一个位置&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;&amp;lt;c-i&amp;gt;&lt;/code&gt;&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;跳到下一个位置&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;&amp;lt;c-b&amp;gt;&lt;/code&gt;&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;上一页&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;&amp;lt;c-f&amp;gt;&lt;/code&gt;&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;下一页&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;&amp;lt;c-u&amp;gt;&lt;/code&gt;&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;上移半屏&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;&amp;lt;c-d&amp;gt;&lt;/code&gt;&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;下移半屏&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;H&lt;/code&gt;&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;调到屏幕顶上&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;M&lt;/code&gt;&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;调到屏幕中间&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;L&lt;/code&gt;&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;调到屏幕下方&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;:n&lt;/code&gt;&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;跳到第 n 行&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;w&lt;/code&gt;&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;跳到下一个单词开头 (标点或空格分隔的单词)&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;W&lt;/code&gt;&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;跳到下一个单词开头 (空格分隔的单词)&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;e&lt;/code&gt;&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;跳到下一个单词尾部 (标点或空格分隔的单词)&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;E&lt;/code&gt;&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;跳到下一个单词尾部 (空格分隔的单词)&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;b&lt;/code&gt;&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;上一个单词头 (标点或空格分隔的单词)&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;B&lt;/code&gt;&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;上一个单词头 (空格分隔的单词)&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;ge&lt;/code&gt;&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;上一个单词尾&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;%&lt;/code&gt;&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;在配对符间移动，可用于 ()、{}、[]&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;gg&lt;/code&gt;&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;到文件首&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;G&lt;/code&gt;&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;到文件尾&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;fx&lt;/code&gt;&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;跳转到下一个为 x 的字符&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;Fx&lt;/code&gt;&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;跳转到上一个为 x 的字符&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;tx&lt;/code&gt;&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;跳转到下一个为 x 的字符前&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;Tx&lt;/code&gt;&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;跳转到上一个为 x 的字符前&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;;&lt;/code&gt;&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;跳到下一个搜索的结果&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;[[&lt;/code&gt;&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;跳转到函数开头&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;]]&lt;/code&gt;&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;跳转到函数结尾&lt;/td&gt;
&lt;/tr&gt;
&lt;/tbody&gt;
&lt;/table&gt;
&lt;h2 id=&#34;文本编辑&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#文本编辑&#34;&gt;#&lt;/a&gt; 文本编辑&lt;/h2&gt;
&lt;table&gt;
&lt;thead&gt;
&lt;tr&gt;
&lt;th&gt;快捷键&lt;/th&gt;
&lt;th&gt;说明&lt;/th&gt;
&lt;/tr&gt;
&lt;/thead&gt;
&lt;tbody&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;r&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;替换当前字符&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;R&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;进入替换模式，直至 ESC 离开&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;s&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;替换字符（删除光标处字符，并进入插入模式，前可接数量）&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;S&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;替换行（删除当前行，并进入插入模式，前可接数量）&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;cc&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;改写当前行（删除当前行并进入插入模式），同 S&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;cw&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;改写光标开始处的当前单词&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;ciw&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;改写光标所处的单词&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;caw&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;改写光标所处的单词，并且包括前后空格（如果有的话）&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;ct,&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;改写到逗号&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;c0&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;改写到行首&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;c^&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;改写到行首（第一个非零字符）&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;c$&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;改写到行末&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;C&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;改写到行末（同 c$）&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;ci&amp;quot;&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;改写双引号中的内容&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;ci&#39;&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;改写单引号中的内容&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;ci)&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;改写小括号中的内容&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;ci]&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;改写中括号中内容&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;ci&amp;#125;&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;改写大括号中内容&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;cit&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;改写 xml tag 中的内容&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;cis&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;改写当前句子&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;ciB&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;改写 &#39;{}&#39; 中的内容&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;c2w&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;改写下两个单词&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;ct(&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;改写到小括号前&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;x&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;删除当前字符，前面可以接数字，3x 代表删除三个字符&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;X&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;向前删除字符&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;dd&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;删除当前行&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;d0&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;删除到行首&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;d^&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;删除到行首（第一个非零字符）&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;d$&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;删除到行末&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;D&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;删除到行末（同 d$）&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;dw&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;删除当前单词&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;dt,&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;删除到逗号&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;diw&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;删除光标所处的单词&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;daw&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;删除光标所处的单词，并包含前后空格（如果有的话）&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;di&amp;quot;&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;删除双引号中的内容&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;di&#39;&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;删除单引号中的内容&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;di)&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;删除小括号中的内容&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;di]&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;删除中括号中内容&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;di&amp;#125;&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;删除大括号中内容&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;diB&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;删除 &#39;{}&#39; 中的内容&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;dit&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;删除 xml tag 中的内容&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;dis&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;删除当前句子&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;d2w&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;删除下两个单词&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;dt(&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;删除到小括号前&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;dgg&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;删除到文件头部&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;dG&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;删除到文件尾部&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;d&amp;#125;&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;删除下一段&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;d&amp;#123;&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;删除上一段&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;u&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;撤销&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;U&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;撤销整行操作&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;CTRL-R&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;撤销上一次 u 命令&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;J&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;连接若干行&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;gJ&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;连接若干行，删除空白字符&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;.&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;重复上一次操作&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;~&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;交换大小写&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;g~iw&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;替换当前单词的大小写&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;gUiw&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;将单词转成大写&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;guiw&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;将当前单词转成小写&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;guu&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;全行转为小写&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;gUU&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;全行转为大写&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;gg=G&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;缩进整个文件&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;=a&amp;#123;&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;缩进光标所在代码块&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;=i&amp;#123;&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;缩进光标所在代码块，不缩进 &amp;quot;{&amp;quot;&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;&amp;lt;&amp;lt;&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;减少缩进&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;&amp;gt;&amp;gt;&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;增加缩进&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;==&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;自动缩进&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;CTRL-A&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;增加数字&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;CTRL-X&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;减少数字&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;p&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;粘贴到光标后&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;P&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;粘贴到光标前&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;v&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;开始标记&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;y&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;复制标记内容&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;V&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;开始按行标记&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;CTRL-V&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;开始列标记&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;y$&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;复制当前位置到本行结束的内容&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;yy&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;复制当前行&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;Y&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;复制当前行，同 yy&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;yt,&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;复制到逗号&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;yiw&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;复制当前单词&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;&amp;quot;+y&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;复制当前选中到系统剪切板&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;3yy&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;复制光标下三行内容&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;v0&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;选中当前位置到行首&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;v$&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;选中当前位置到行末&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;vt,&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;选中到逗号&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;viw&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;选中当前单词&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;vi)&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;选中小括号内的东西&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;vi]&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;选中中括号内的东西&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;viB&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;选中 &#39;{}&#39; 中的内容&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;vis&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;选中句子中的东西&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;gv&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;重新选择上一次选中的文字&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;:set paste&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;允许粘贴模式（避免粘贴时自动缩进影响格式）&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;:set nopaste&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;禁止粘贴模式&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;&amp;quot;?yy&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;复制当前行到寄存器？，问号代表 0-9 的寄存器名称&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;&amp;quot;?p&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;将寄存器？的内容粘贴到光标后&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;&amp;quot;?P&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;将寄存器？的内容粘贴到光标前&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;:registers&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;显示所有寄存器内容&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;:[range]y&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;复制范围，比如 :20,30y 是复制 20 到 30 行，:10y 是复制第十行&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;:[range]d&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;删除范围，比如 :20,30d 是删除 20 到 30 行，:10d 是删除第十行&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;ddp&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;交换两行内容：先删除当前行复制到寄存器，并粘贴&lt;/td&gt;
&lt;/tr&gt;
&lt;/tbody&gt;
&lt;/table&gt;
&lt;h2 id=&#34;文件操作&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#文件操作&#34;&gt;#&lt;/a&gt; 文件操作&lt;/h2&gt;
&lt;table&gt;
&lt;thead&gt;
&lt;tr&gt;
&lt;th&gt;快捷键&lt;/th&gt;
&lt;th&gt;说明&lt;/th&gt;
&lt;/tr&gt;
&lt;/thead&gt;
&lt;tbody&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;:w&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;保存文件&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;:w &amp;lt;filename&amp;gt;&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;按名称保存文件&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;ZZ&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;保存文件（如果有改动的话），并关闭窗口&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;:e &amp;lt;filename&amp;gt;&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;打开文件并编辑&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;:saveas &amp;lt;filename&amp;gt;&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;另存为文件&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;:r &amp;lt;filename&amp;gt;&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;读取文件并将内容插入到光标后&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;:r !dir&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;将 dir 命令的输出捕获并插入到光标后&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;:close&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;关闭文件&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;:q&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;退出&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;:q!&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;强制退出&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;:wa&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;保存所有文件&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;:cd &amp;lt;path&amp;gt;&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;切换 Vim 当前路径&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;:new&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;打开一个新的窗口编辑新文件&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;:enew&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;在当前窗口创建新文件&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;:vnew&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;在左右切分的新窗口中编辑新文件&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;:tabnew&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;在新的标签页中编辑新文件&lt;/td&gt;
&lt;/tr&gt;
&lt;/tbody&gt;
&lt;/table&gt;
&lt;h2 id=&#34;使用外部程序&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#使用外部程序&#34;&gt;#&lt;/a&gt; 使用外部程序&lt;/h2&gt;
&lt;table&gt;
&lt;thead&gt;
&lt;tr&gt;
&lt;th&gt;快捷键&lt;/th&gt;
&lt;th&gt;说明&lt;/th&gt;
&lt;/tr&gt;
&lt;/thead&gt;
&lt;tbody&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;!&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;告诉 vim 正在执行一个过滤操作&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;!5Gsort&amp;lt;Enter&amp;gt;&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;使用外部 sort 命令对 1-5 行文本排序&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;!!&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;对当前行执行过滤命令&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;!!date&amp;lt;Enter&amp;gt;&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;用 &amp;quot;date&amp;quot; 的输出代替当前行&lt;/td&gt;
&lt;/tr&gt;
&lt;/tbody&gt;
&lt;/table&gt;
&lt;h2 id=&#34;宏录制&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#宏录制&#34;&gt;#&lt;/a&gt; 宏录制&lt;/h2&gt;
&lt;table&gt;
&lt;thead&gt;
&lt;tr&gt;
&lt;th&gt;快捷键&lt;/th&gt;
&lt;th&gt;说明&lt;/th&gt;
&lt;/tr&gt;
&lt;/thead&gt;
&lt;tbody&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;qa&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;开始录制名字为 a 的宏&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;q&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;结束录制宏&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;@a&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;播放名字为 a 的宏&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;100@a&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;播放名字为 a 的宏 100 次&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;:normal@a&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;播放名字为 a 的宏直到自动结束&lt;/td&gt;
&lt;/tr&gt;
&lt;/tbody&gt;
&lt;/table&gt;
&lt;h2 id=&#34;实用命令&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#实用命令&#34;&gt;#&lt;/a&gt; 实用命令&lt;/h2&gt;
&lt;table&gt;
&lt;thead&gt;
&lt;tr&gt;
&lt;th&gt;快捷键&lt;/th&gt;
&lt;th&gt;说明&lt;/th&gt;
&lt;/tr&gt;
&lt;/thead&gt;
&lt;tbody&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;/pattern&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;从光标处向文件尾搜索 pattern&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;?pattern&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;从光标处向文件头搜索 pattern&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;n&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;向同一方向执行上一次搜索&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;N&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;向相反方向执行上一次搜索&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;*&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;向前搜索光标下的单词&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;#&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;向后搜索光标下的单词&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;:s/p1/p2/g&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;替换当前行的 p1 为 p2&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;:%s/p1/p2/g&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;替换当前文件中的 p1 为 p2&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;:%s/&amp;lt;p1&amp;gt;/p2/g&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;替换当前文件中的 p1 单词为 p2&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;:%s/p1/p2/gc&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;替换当前文件中的 p1 为 p2，并且每处询问你是否替换&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;:10,20s/p1/p2/g&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;将第 10 到 20 行中所有 p1 替换为 p2&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;:%s/1\\2\/3/123/g&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;将 “1\2/3” 替换为 “123”（特殊字符使用反斜杠标注）&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;:%s/\r//g&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;删除 DOS 换行符 ^M&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;:g/^\s*$/d&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;删除空行&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;:g/test/d&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;删除所有包含 test 的行&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;:v/test/d&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;删除所有不包含 test 的行&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;:%s/^/test/&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;在行首加入特定字符 (也可以用宏录制来添加)&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;:%s/$/test/&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;在行尾加入特定字符 (也可以用宏录制来添加)&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;:sort&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;排序&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;:g/^\(.\+\)$\n\1/d&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;去除重复行 (先排序)&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;:%s/^.\&amp;#123;10\&amp;#125;//&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;删除每行前 10 个字符&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;:%s/.\&amp;#123;10\&amp;#125;$//&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;删除每行尾 10 个字符&lt;/td&gt;
&lt;/tr&gt;
&lt;/tbody&gt;
&lt;/table&gt;
&lt;h2 id=&#34;帮助&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#帮助&#34;&gt;#&lt;/a&gt; 帮助&lt;/h2&gt;
&lt;table&gt;
&lt;thead&gt;
&lt;tr&gt;
&lt;th&gt;快捷键&lt;/th&gt;
&lt;th&gt;说明&lt;/th&gt;
&lt;/tr&gt;
&lt;/thead&gt;
&lt;tbody&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;h tutor&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;入门文档&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;h quickref&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;快速帮助&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;h index&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;查询 Vim 所有键盘命令定义&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;h summary&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;帮助你更好的使用内置帮助系统&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;h pattern.txt&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;正则表达式帮助&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;h eval&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;脚本编写帮助&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;h function-list&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;查看 VimScript 的函数列表&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;h windows.txt&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;窗口使用帮助&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;h tabpage.txt&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;标签页使用帮助&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;h tips&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;查看 Vim 内置的常用技巧文档&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;h quote&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;寄存器&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;h autocommand-events&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;所有可能事件&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;h write-plugin&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;编写插件&lt;/td&gt;
&lt;/tr&gt;
&lt;/tbody&gt;
&lt;/table&gt;
&lt;h2 id=&#34;其他&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#其他&#34;&gt;#&lt;/a&gt; 其他&lt;/h2&gt;
&lt;table&gt;
&lt;thead&gt;
&lt;tr&gt;
&lt;th&gt;快捷键&lt;/th&gt;
&lt;th&gt;说明&lt;/th&gt;
&lt;/tr&gt;
&lt;/thead&gt;
&lt;tbody&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;vim -u NONE -N&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;开启 vim 时不加载 vimrc 文件&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;vimdiff file1 file2&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;显示文件差异&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;vim -R filename&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;以只读方式打开（阅读模式）&lt;/td&gt;
&lt;/tr&gt;
&lt;/tbody&gt;
&lt;/table&gt;
&lt;p&gt;/ 字符串 查找字符串 n 向下查找 N 向上查找&lt;br /&gt;
？字符串 查找字符串&lt;br /&gt;
 #-- 把光标方到字符串上再按 #键&lt;br /&gt;
缩进 &amp;gt;&amp;gt; &amp;lt;&amp;lt;&lt;br /&gt;
shift+K 光标所在字符串跳转到 man&lt;/p&gt;
&lt;p&gt;😒/ 要替换的字符串 / 字符串&lt;br /&gt;
😒/ 要替换的字符串 / 字符串 /g 光标所在行全部替换&lt;br /&gt;
:% s/   /g 全部替换&lt;br /&gt;
:[low],[ high] s / 字符串 / 字符串 /g&lt;/p&gt;
&lt;p&gt;执行命令&lt;/p&gt;
&lt;p&gt;:![command]&lt;/p&gt;
&lt;p&gt;命令模式下 ZZ 保存退出&lt;/p&gt;
&lt;p&gt;:sp 水平分屏&lt;br /&gt;
水平分屏切换 ctrl+WW&lt;br /&gt;
:vsp 垂直分屏&lt;br /&gt;
垂直分屏切换 ctrl+WW&lt;/p&gt;
&lt;script type=&#34;text&amp;#x2F;javascript&#34; src=&#34;https://cdn.jsdelivr.net/npm/kity@2.0.4/dist/kity.min.js&#34;&gt;&lt;/script&gt;&lt;script type=&#34;text&amp;#x2F;javascript&#34; src=&#34;https://cdn.jsdelivr.net/npm/kityminder-core@1.4.50/dist/kityminder.core.min.js&#34;&gt;&lt;/script&gt;&lt;script defer=&#34;true&#34; type=&#34;text&amp;#x2F;javascript&#34; src=&#34;https://cdn.jsdelivr.net/npm/hexo-simple-mindmap@0.7.0/dist/mindmap.min.js&#34;&gt;&lt;/script&gt;&lt;link rel=&#34;stylesheet&#34; type=&#34;text&amp;#x2F;css&#34; href=&#34;https://cdn.jsdelivr.net/npm/hexo-simple-mindmap@0.7.0/dist/mindmap.min.css&#34;&gt;

 &lt;h2 id=&#34;git配置&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#git配置&#34;&gt;#&lt;/a&gt; Git 配置&lt;/h2&gt;
&lt;p&gt;&lt;code&gt;git config&lt;/code&gt;   配置或读取相应的工作环境变量&lt;/p&gt;
&lt;h3 id=&#34;配置信息的存放位置&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#配置信息的存放位置&#34;&gt;#&lt;/a&gt; 配置信息的存放位置&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;&lt;code&gt;/etc/gitconfig&lt;/code&gt;  文件
&lt;ul&gt;
&lt;li&gt;该文件存放的是系统中所有用户都适用的配置信息&lt;/li&gt;
&lt;li&gt;&lt;code&gt;git config --system&lt;/code&gt;  这个命令就是对 &lt;code&gt;/etc/gitconfig&lt;/code&gt;  文件进行读写操作&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;&lt;code&gt;~/.gitconfig&lt;/code&gt;  文件
&lt;ul&gt;
&lt;li&gt;这个文件是存放当前用户的配置信息&lt;/li&gt;
&lt;li&gt;&lt;code&gt;git config --global&lt;/code&gt;   这个命令就是对 &lt;code&gt;~/.gitconfig&lt;/code&gt;  文件进行读写操作&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;git 一般情况下优先读写 &lt;code&gt;~/.gitconfig&lt;/code&gt;  文件，然后再读取 &lt;code&gt;/etc/gitconfig&lt;/code&gt;  文件。&lt;/li&gt;
&lt;/ul&gt;
&lt;h3 id=&#34;配置用户信息&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#配置用户信息&#34;&gt;#&lt;/a&gt; 配置用户信息&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;&lt;code&gt;git config --global user.name &amp;quot;user_name&amp;quot;&lt;/code&gt;&lt;/li&gt;
&lt;li&gt;&lt;code&gt;git config --global user.emial &amp;quot;your_email&amp;quot;&lt;/code&gt;&lt;/li&gt;
&lt;li&gt;使用上述两条命令，就是在你的配置文件中写入你的用户信息，此后所有的 git 项目都会默认的使用你的配置文件中的用户信息&lt;/li&gt;
&lt;li&gt;当然你也可以单独的为你的每一个 git 项目配置用户信息，只需要将 &lt;code&gt;--global&lt;/code&gt;  选项去掉即可，此时新的设定将会保存在你的当前 git 项目的 &lt;code&gt;.git/config&lt;/code&gt;  文件里&lt;/li&gt;
&lt;/ul&gt;
&lt;h3 id=&#34;为git配置你熟悉的文本编辑器&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#为git配置你熟悉的文本编辑器&#34;&gt;#&lt;/a&gt; 为 git 配置你熟悉的文本编辑器&lt;/h3&gt;
&lt;p&gt;&lt;code&gt;git config --global core.editor &amp;quot;your_editor_name&amp;quot;&lt;/code&gt;&lt;/p&gt;
&lt;p&gt;如果你的编辑器名字有空格，请用双引号 &amp;quot;&amp;quot; 将其括起来&lt;/p&gt;
&lt;h3 id=&#34;配置差异分析工具&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#配置差异分析工具&#34;&gt;#&lt;/a&gt; 配置差异分析工具&lt;/h3&gt;
&lt;p&gt;用于解决合并冲突时的分析工具&lt;/p&gt;
&lt;p&gt;&lt;code&gt;git config --global merge.tool &amp;quot;diff_tool_name&amp;quot;&lt;/code&gt;&lt;/p&gt;
&lt;p&gt;使用什么差异分析工具就使用它的名字即可，如 &lt;code&gt;vimdiff&lt;/code&gt;&lt;/p&gt;
&lt;p&gt;git 可以理解的差异分析工具有&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;&lt;code&gt;kdiff3&lt;/code&gt;&lt;/li&gt;
&lt;li&gt;&lt;code&gt;tkdiff&lt;/code&gt;&lt;/li&gt;
&lt;li&gt;&lt;code&gt;meld&lt;/code&gt;&lt;/li&gt;
&lt;li&gt;&lt;code&gt;xxdiff&lt;/code&gt;&lt;/li&gt;
&lt;li&gt;&lt;code&gt;emerge&lt;/code&gt;&lt;/li&gt;
&lt;li&gt;&lt;code&gt;vimdiff&lt;/code&gt;&lt;/li&gt;
&lt;li&gt;&lt;code&gt;gvimdiff&lt;/code&gt;&lt;/li&gt;
&lt;li&gt;&lt;code&gt;ecmerge&lt;/code&gt;&lt;/li&gt;
&lt;li&gt;&lt;code&gt;opendiff&lt;/code&gt;&lt;/li&gt;
&lt;/ul&gt;
&lt;h3 id=&#34;查看配置信息&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#查看配置信息&#34;&gt;#&lt;/a&gt; 查看配置信息&lt;/h3&gt;
&lt;p&gt;&lt;code&gt;git config --list&lt;/code&gt;&lt;/p&gt;
&lt;h2 id=&#34;git工作区-暂存区和版本库&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#git工作区-暂存区和版本库&#34;&gt;#&lt;/a&gt; Git 工作区、暂存区和版本库&lt;/h2&gt;
&lt;h3 id=&#34;基本概念&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#基本概念&#34;&gt;#&lt;/a&gt; 基本概念&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;工作区：本地 git 目录，即 &lt;code&gt;.git&lt;/code&gt;  所在目录为 git 工作区&lt;/li&gt;
&lt;li&gt;暂存区：又叫索引区，存放于.git 目录下的 index 文件中&lt;/li&gt;
&lt;li&gt;版本库：工作区中的一个隐藏目录 &lt;code&gt;.git&lt;/code&gt; ,  &lt;code&gt;.git&lt;/code&gt;  不属于工作区，它仅仅是一个 Git 的版本库&lt;/li&gt;
&lt;/ul&gt;
&lt;h3 id=&#34;工作区-暂存区和版本库的关系&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#工作区-暂存区和版本库的关系&#34;&gt;#&lt;/a&gt; 工作区、暂存区和版本库的关系&lt;/h3&gt;
&lt;ol&gt;
&lt;li&gt;工作区和版本库是独立的两个部分，虽然版本库存在于工作区中&lt;/li&gt;
&lt;li&gt;版本库中包含了暂存区、对象库、分支等信息&lt;/li&gt;
&lt;li&gt;分支是一个目录树，用一个 &amp;quot;HEAD&amp;quot; 的游标指向这个分支&lt;/li&gt;
&lt;li&gt;对象库存放于 &lt;code&gt;.git/objects&lt;/code&gt;  目录中，它包含了创建的各种对象以及内容&lt;/li&gt;
&lt;/ol&gt;
&lt;p&gt;&lt;a href=&#34;https://imgtu.com/i/Og2FL4&#34;&gt;&lt;img data-src=&#34;https://s1.ax1x.com/2022/05/15/Og2FL4.png&#34; alt=&#34;Og2FL4.png&#34; /&gt;&lt;/a&gt;&lt;/p&gt;
&lt;h4 id=&#34;git-add的运行过程&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#git-add的运行过程&#34;&gt;#&lt;/a&gt;  &lt;code&gt;git add&lt;/code&gt;  的运行过程&lt;/h4&gt;
&lt;p&gt;当使用 &lt;code&gt;git add&lt;/code&gt;  命令后，暂存区的目录树会被更新，同时工作区修改的文件内容会被写入到对象库中的一个新对象中，而该对象的 ID 被记录在暂存区的文件索引中&lt;/p&gt;
&lt;p&gt;&lt;strong&gt;将工作区修改的内容写入到暂存区&lt;/strong&gt;&lt;/p&gt;
&lt;h4 id=&#34;git-commit的运行过程&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#git-commit的运行过程&#34;&gt;#&lt;/a&gt;  &lt;code&gt;git commit&lt;/code&gt;  的运行过程&lt;/h4&gt;
&lt;p&gt;执行 &lt;code&gt;git commit&lt;/code&gt;  命令时，暂存区的目录树写入到版本库（对象库）中，master 分支会做相应的更新，即 master 指向的目录树就是提交时暂时缓存的目录树。&lt;/p&gt;
&lt;p&gt;&lt;strong&gt;将暂存区中的内容写入到 master 指向的分支&lt;/strong&gt;&lt;/p&gt;
&lt;h4 id=&#34;git-reset-head的运行过程&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#git-reset-head的运行过程&#34;&gt;#&lt;/a&gt;  &lt;code&gt;git reset HEAD&lt;/code&gt;  的运行过程&lt;/h4&gt;
&lt;p&gt;执行 &lt;code&gt;git reset HEAD&lt;/code&gt;  命令时，暂存区的目录树会被重写，被 master 分支指向的目录所替换，但是工作区不受影响。&lt;/p&gt;
&lt;p&gt;&lt;strong&gt;将 master 分支中的目录树写入到暂存区中&lt;/strong&gt;&lt;/p&gt;
&lt;p&gt;&lt;code&gt;git rm --cached &amp;lt;file&amp;gt;&lt;/code&gt;  &lt;strong&gt;直接从暂存区删除文件，工作区则不做出改变&lt;/strong&gt;&lt;/p&gt;
&lt;p&gt;&lt;code&gt;git checkout .&lt;/code&gt;  或 &lt;code&gt;git checkout -- &amp;lt;file&amp;gt;&lt;/code&gt;   &lt;strong&gt;用暂存区全部或指定的文件替换工作区的文件&lt;/strong&gt;。这个操作很危险，会清除工作区中未添加到暂存区中的改动。&lt;/p&gt;
&lt;p&gt;&lt;code&gt;git checkout HEAD .&lt;/code&gt;  或者 &lt;code&gt;git checkout HEAD &amp;lt;file&amp;gt;&lt;/code&gt;  ** 用 HEAD 指向的 master 分支中的全部或者部分文件替换暂存区和以及工作区中的文件。** 这个命令也是极具危险性的，因为不但会清除工作区中未提交的改动，也会清除暂存区中未提交的改动。&lt;/p&gt;
&lt;h2 id=&#34;git创建仓库&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#git创建仓库&#34;&gt;#&lt;/a&gt; Git 创建仓库&lt;/h2&gt;
&lt;figure class=&#34;highlight shell&#34;&gt;&lt;figcaption data-lang=&#34;Bash&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token comment&#34;&gt;# 初始化&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;2&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token function&#34;&gt;git&lt;/span&gt; init &lt;span class=&#34;token comment&#34;&gt;#在当前目录中初始化一个仓库&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;3&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token function&#34;&gt;git&lt;/span&gt; init repo_name &lt;span class=&#34;token comment&#34;&gt;#指定一个目录名创建仓库&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;4&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token comment&#34;&gt;# 克隆远程项目&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;5&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token function&#34;&gt;git&lt;/span&gt; clone &lt;span class=&#34;token operator&#34;&gt;&amp;lt;&lt;/span&gt;远程仓库链接&lt;span class=&#34;token operator&#34;&gt;&gt;&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;[&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;&amp;lt;&lt;/span&gt;存放目录路径&lt;span class=&#34;token operator&#34;&gt;&gt;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;]&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;h2 id=&#34;git基本操作&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#git基本操作&#34;&gt;#&lt;/a&gt; Git 基本操作&lt;/h2&gt;
&lt;h3 id=&#34;git常用命令&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#git常用命令&#34;&gt;#&lt;/a&gt; Git 常用命令&lt;/h3&gt;
&lt;h4 id=&#34;创建仓库命令&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#创建仓库命令&#34;&gt;#&lt;/a&gt; 创建仓库命令&lt;/h4&gt;
&lt;figure class=&#34;highlight shell&#34;&gt;&lt;figcaption data-lang=&#34;Bash&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token comment&#34;&gt;# 初始化一个仓库&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;2&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token function&#34;&gt;git&lt;/span&gt; init &lt;span class=&#34;token punctuation&#34;&gt;[&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;&amp;lt;&lt;/span&gt;direction&lt;span class=&#34;token operator&#34;&gt;&gt;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;]&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;3&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token comment&#34;&gt;# 拷贝一个远程仓库&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;4&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token function&#34;&gt;git&lt;/span&gt; clone &lt;span class=&#34;token operator&#34;&gt;&amp;lt;&lt;/span&gt;repository-link&lt;span class=&#34;token operator&#34;&gt;&gt;&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;[&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;&amp;lt;&lt;/span&gt;direction&lt;span class=&#34;token operator&#34;&gt;&gt;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;]&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;h4 id=&#34;提交与修改&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#提交与修改&#34;&gt;#&lt;/a&gt; 提交与修改&lt;/h4&gt;
&lt;figure class=&#34;highlight shell&#34;&gt;&lt;figcaption data-lang=&#34;Bash&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token comment&#34;&gt;# 添加文件到暂存区&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;2&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token function&#34;&gt;git&lt;/span&gt; &lt;span class=&#34;token function&#34;&gt;add&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;3&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token function&#34;&gt;git&lt;/span&gt; &lt;span class=&#34;token function&#34;&gt;add&lt;/span&gt; * &lt;span class=&#34;token comment&#34;&gt;# 将工作区中的所有文件都添加到暂存区&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;4&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token function&#34;&gt;git&lt;/span&gt; &lt;span class=&#34;token function&#34;&gt;add&lt;/span&gt; &lt;span class=&#34;token builtin class-name&#34;&gt;.&lt;/span&gt; &lt;span class=&#34;token comment&#34;&gt;# 将工作区中修改过的文件添加到暂存区&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;5&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token function&#34;&gt;git&lt;/span&gt; &lt;span class=&#34;token function&#34;&gt;add&lt;/span&gt; &lt;span class=&#34;token operator&#34;&gt;&amp;lt;&lt;/span&gt;file&lt;span class=&#34;token operator&#34;&gt;&gt;&lt;/span&gt; &lt;span class=&#34;token comment&#34;&gt;# 指定工作区的文件添加到暂存区&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;6&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;7&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token comment&#34;&gt;# 查看仓库当前状态，显示有变更的文件&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;8&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token function&#34;&gt;git&lt;/span&gt; status&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;9&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;10&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token comment&#34;&gt;# 比较文件的不同，即暂存区和工作区的差异&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;11&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token function&#34;&gt;git&lt;/span&gt; &lt;span class=&#34;token function&#34;&gt;diff&lt;/span&gt; &lt;span class=&#34;token operator&#34;&gt;&amp;lt;&lt;/span&gt;file&lt;span class=&#34;token operator&#34;&gt;&gt;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;12&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;13&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token comment&#34;&gt;# 提交暂存区内容到分支中&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;14&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token function&#34;&gt;git&lt;/span&gt; commit &lt;span class=&#34;token punctuation&#34;&gt;[&lt;/span&gt;-m &lt;span class=&#34;token string&#34;&gt;&#34;提示(promt)&#34;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;]&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;15&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;16&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token comment&#34;&gt;# 回退版本 &lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;17&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token function&#34;&gt;git&lt;/span&gt; reset&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;18&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;19&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token comment&#34;&gt;# 删除工作区文件&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;20&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token function&#34;&gt;git&lt;/span&gt; &lt;span class=&#34;token function&#34;&gt;rm&lt;/span&gt; &lt;span class=&#34;token operator&#34;&gt;&amp;lt;&lt;/span&gt;file&lt;span class=&#34;token operator&#34;&gt;&gt;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;21&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;22&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token comment&#34;&gt;# 移动或重命名工作区文件&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;23&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token function&#34;&gt;git&lt;/span&gt; &lt;span class=&#34;token function&#34;&gt;mv&lt;/span&gt; &lt;span class=&#34;token operator&#34;&gt;&amp;lt;&lt;/span&gt;oldfile&lt;span class=&#34;token operator&#34;&gt;&gt;&lt;/span&gt; &lt;span class=&#34;token operator&#34;&gt;&amp;lt;&lt;/span&gt;newfile&lt;span class=&#34;token operator&#34;&gt;&gt;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;h4 id=&#34;提交日志&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#提交日志&#34;&gt;#&lt;/a&gt; 提交日志&lt;/h4&gt;
&lt;figure class=&#34;highlight shell&#34;&gt;&lt;figcaption data-lang=&#34;Bash&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token comment&#34;&gt;# 查看日志记录&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;2&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token function&#34;&gt;git&lt;/span&gt; log&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;3&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;4&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token comment&#34;&gt;# 以列表的形式查看指定文件的历史修改记录&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;5&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token function&#34;&gt;git&lt;/span&gt; blame &lt;span class=&#34;token operator&#34;&gt;&amp;lt;&lt;/span&gt;file&lt;span class=&#34;token operator&#34;&gt;&gt;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;h4 id=&#34;远程操作&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#远程操作&#34;&gt;#&lt;/a&gt; 远程操作&lt;/h4&gt;
&lt;figure class=&#34;highlight shell&#34;&gt;&lt;figcaption data-lang=&#34;Bash&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token comment&#34;&gt;# 远程仓库操作&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;2&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token function&#34;&gt;git&lt;/span&gt; remote&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;3&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;4&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token comment&#34;&gt;# 从远程获取代码库&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;5&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token function&#34;&gt;git&lt;/span&gt; fetch&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;6&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;7&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token comment&#34;&gt;# 下载远程代码并合并&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;8&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token function&#34;&gt;git&lt;/span&gt; pull&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;9&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;10&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token comment&#34;&gt;# 上传远程代码并合并&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;h2 id=&#34;git分支管理&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#git分支管理&#34;&gt;#&lt;/a&gt; Git 分支管理&lt;/h2&gt;
&lt;h3 id=&#34;分支管理常用命令&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#分支管理常用命令&#34;&gt;#&lt;/a&gt; 分支管理常用命令&lt;/h3&gt;
&lt;figure class=&#34;highlight shell&#34;&gt;&lt;figcaption data-lang=&#34;Bash&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token comment&#34;&gt;# 创建分支&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;2&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token function&#34;&gt;git&lt;/span&gt; branch &lt;span class=&#34;token operator&#34;&gt;&amp;lt;&lt;/span&gt;branch_name&lt;span class=&#34;token operator&#34;&gt;&gt;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;3&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token comment&#34;&gt;# 切换分支&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;4&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token function&#34;&gt;git&lt;/span&gt; checkout &lt;span class=&#34;token operator&#34;&gt;&amp;lt;&lt;/span&gt;brach_name&lt;span class=&#34;token operator&#34;&gt;&gt;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;5&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token comment&#34;&gt;# 合并分支&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;6&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token function&#34;&gt;git&lt;/span&gt; merge&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;h3 id=&#34;分支管理操作&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#分支管理操作&#34;&gt;#&lt;/a&gt; 分支管理操作&lt;/h3&gt;
&lt;h4 id=&#34;列出分支&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#列出分支&#34;&gt;#&lt;/a&gt; 列出分支&lt;/h4&gt;
&lt;p&gt;&lt;code&gt;git branch&lt;/code&gt;  列出分支&lt;/p&gt;
&lt;p&gt;例子：使用 &lt;code&gt;git branch&lt;/code&gt;  命令创建一个分支并切换到新的分支上，提交当前修该的内容&lt;/p&gt;
&lt;figure class=&#34;highlight shell&#34;&gt;&lt;figcaption data-lang=&#34;Bash&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token comment&#34;&gt;# 创建分支&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;2&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token function&#34;&gt;git&lt;/span&gt; branch newbranch&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;3&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token comment&#34;&gt;# 列出所有分支，查看是否分支创建成功&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;4&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token function&#34;&gt;git&lt;/span&gt; branch&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;5&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token comment&#34;&gt;# 切换到新建分支中&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;6&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token function&#34;&gt;git&lt;/span&gt; checkout newbranch&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;7&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;8&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token comment&#34;&gt;# 在当前工作区修改内容&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;9&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token comment&#34;&gt;# ...&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;10&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token comment&#34;&gt;# ...&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;11&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;12&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token comment&#34;&gt;# 提交修改到暂存区&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;13&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token function&#34;&gt;git&lt;/span&gt; &lt;span class=&#34;token function&#34;&gt;add&lt;/span&gt; &lt;span class=&#34;token builtin class-name&#34;&gt;.&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;14&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token comment&#34;&gt;# 将暂存区的内容提到 newbranch 中&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;15&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token function&#34;&gt;git&lt;/span&gt; commit -m &lt;span class=&#34;token string&#34;&gt;&#34;promt&#34;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;p&gt;我们也可以使用 &lt;code&gt;git branch -b &amp;lt;branch_name&amp;gt;&lt;/code&gt;  来创建一个新分支并切换到新建的分支上&lt;/p&gt;
&lt;h4 id=&#34;删除分支&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#删除分支&#34;&gt;#&lt;/a&gt; 删除分支&lt;/h4&gt;
&lt;p&gt;&lt;code&gt;git branch -d &amp;lt;branch_name&amp;gt;&lt;/code&gt;  删除分支&lt;/p&gt;
&lt;p&gt;例子：删除上述添加的分支&lt;/p&gt;
&lt;figure class=&#34;highlight shell&#34;&gt;&lt;figcaption data-lang=&#34;Bash&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token function&#34;&gt;git&lt;/span&gt; branch -d newbrach&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;h4 id=&#34;分支合并&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#分支合并&#34;&gt;#&lt;/a&gt; 分支合并&lt;/h4&gt;
&lt;p&gt;&lt;code&gt;git merge &amp;lt;branch_name&amp;gt;&lt;/code&gt;  合并分支&lt;/p&gt;
&lt;p&gt;例子：将上述的 &lt;code&gt;newbranch&lt;/code&gt;  分支合并到主分支中然后删除分支&lt;/p&gt;
&lt;figure class=&#34;highlight shell&#34;&gt;&lt;figcaption data-lang=&#34;Bash&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token comment&#34;&gt;# 列出当前分支&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;2&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token function&#34;&gt;git&lt;/span&gt; branch&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;3&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token comment&#34;&gt;# 合并分支&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;4&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token function&#34;&gt;git&lt;/span&gt; merge newbranch&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;5&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token comment&#34;&gt;# 删除 nerbranch 分支&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;6&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token function&#34;&gt;git&lt;/span&gt; branch -d newbranch&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;7&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token comment&#34;&gt;# 列出分支，查看是否删除成功&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;8&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token function&#34;&gt;git&lt;/span&gt; brach&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;h4 id=&#34;合并冲突的解决&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#合并冲突的解决&#34;&gt;#&lt;/a&gt; 合并冲突的解决&lt;/h4&gt;
&lt;figure class=&#34;highlight shell&#34;&gt;&lt;figcaption data-lang=&#34;Bash&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token comment&#34;&gt;# 合并产生冲突时，会提示我们是那些文件产生的合并冲突&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;2&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token comment&#34;&gt;# 因此我们可以根据提示打开文件，查看冲突内容，然后修改即可&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;3&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;4&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token function&#34;&gt;cat&lt;/span&gt; 产生冲突的文件 &lt;span class=&#34;token comment&#34;&gt;# 查看冲突&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;5&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token function&#34;&gt;vim&lt;/span&gt; 产生冲突的文件 &lt;span class=&#34;token comment&#34;&gt;# 修改文件&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;6&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token function&#34;&gt;git&lt;/span&gt; &lt;span class=&#34;token function&#34;&gt;diff&lt;/span&gt; &lt;span class=&#34;token comment&#34;&gt;# 查看文件修改前后的差异&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;7&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token function&#34;&gt;git&lt;/span&gt; status -s &lt;span class=&#34;token comment&#34;&gt;# 查看 git 当前状态&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;8&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token function&#34;&gt;git&lt;/span&gt; &lt;span class=&#34;token function&#34;&gt;add&lt;/span&gt; 产生冲突的文件 &lt;span class=&#34;token comment&#34;&gt;# 告诉 git 冲突已经解决&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;9&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token function&#34;&gt;git&lt;/span&gt; status -s &lt;span class=&#34;token comment&#34;&gt;# 查看当前状态&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;10&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token function&#34;&gt;git&lt;/span&gt; commit &lt;span class=&#34;token comment&#34;&gt;# 提交到 master 分支&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;h2 id=&#34;查看提交历史&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#查看提交历史&#34;&gt;#&lt;/a&gt; 查看提交历史&lt;/h2&gt;
&lt;ol&gt;
&lt;li&gt;&lt;code&gt;git log&lt;/code&gt;&lt;/li&gt;
&lt;li&gt;&lt;code&gt;git blame &amp;lt;file&amp;gt;&lt;/code&gt;   以列表的形式查看指定文件的历史修改记录&lt;/li&gt;
&lt;/ol&gt;
&lt;figure class=&#34;highlight shell&#34;&gt;&lt;figcaption data-lang=&#34;Bash&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token function&#34;&gt;git&lt;/span&gt; log --oneline（简洁） &lt;span class=&#34;token comment&#34;&gt;# 查看历史记录的简洁版本&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;2&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token function&#34;&gt;git&lt;/span&gt; log --graph&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;拓扑图&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;  &lt;span class=&#34;token comment&#34;&gt;# 查看历史中什么时候出现分支、合并&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;3&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token function&#34;&gt;git&lt;/span&gt; log --reverse --onlie &lt;span class=&#34;token comment&#34;&gt;# 逆向显示所有日志&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;4&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token function&#34;&gt;git&lt;/span&gt; log --author&lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt;&lt;span class=&#34;token string&#34;&gt;&#34;name&#34;&lt;/span&gt; &lt;span class=&#34;token comment&#34;&gt;# 查找指定用户的提高日志&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;5&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token function&#34;&gt;git&lt;/span&gt; log --oneline --before&lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;&lt;span class=&#34;token number&#34;&gt;3&lt;/span&gt;.weeks.ago&lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt; --after&lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;&lt;span class=&#34;token number&#34;&gt;2021&lt;/span&gt;-01-01&lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt; --no-merges &lt;span class=&#34;token comment&#34;&gt;# 查看三周以前，2021 年 01 月 01 日之后的没有合并的日志&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;6&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token comment&#34;&gt;# 还有 --until --since 可用&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;h2 id=&#34;git标签&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#git标签&#34;&gt;#&lt;/a&gt; Git 标签&lt;/h2&gt;
&lt;p&gt;&lt;code&gt;git tag&lt;/code&gt;  就是给你当前项目的某一个阶段打标签&lt;/p&gt;
&lt;p&gt;&lt;code&gt;git tag -a 注释&lt;/code&gt;  创建一个带有注释的标签&lt;/p&gt;
&lt;p&gt;&lt;code&gt;git log --decorate&lt;/code&gt;  可以查看历史标签&lt;/p&gt;
&lt;p&gt;&lt;code&gt;git tag -a 注释  提交的序列号&lt;/code&gt;&lt;/p&gt;
&lt;p&gt;&lt;code&gt;git tag&lt;/code&gt;  查看所有标签&lt;/p&gt;
&lt;p&gt;&lt;code&gt;git tag -a &amp;lt;tagname&amp;gt; -m &amp;quot;注释&amp;quot;&lt;/code&gt;  指定标签信息&lt;/p&gt;
&lt;p&gt;&lt;code&gt;git tag -s &amp;lt;tagname&amp;gt; -m &amp;quot;注释&amp;quot; &lt;/code&gt;  PGP 签名标签&lt;/p&gt;
&lt;h2 id=&#34;github&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#github&#34;&gt;#&lt;/a&gt; Github&lt;/h2&gt;
&lt;figure class=&#34;highlight shell&#34;&gt;&lt;figcaption data-lang=&#34;Bash&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token comment&#34;&gt;# 生成 ssh key&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;2&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;ssh-keygen -t rsa -C &lt;span class=&#34;token string&#34;&gt;&#34;your-email@example&#34;&lt;/span&gt; &lt;span class=&#34;token comment&#34;&gt;# 邮件为关联了 github 的邮件&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;3&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token comment&#34;&gt;# 进入到生成的 &#39;~/.ssh&#39; 目录中将公钥 id_rsa.pub 中的内容复制到你的 github 上，即 `SSH and GPG keys` 中&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;4&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token comment&#34;&gt;# 验证是否成功&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;5&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token function&#34;&gt;ssh&lt;/span&gt; -T git@github.com&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;6&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token comment&#34;&gt;# 初始化&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;7&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token function&#34;&gt;git&lt;/span&gt; init&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;8&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token comment&#34;&gt;# 添加文件&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;9&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token function&#34;&gt;git&lt;/span&gt; &lt;span class=&#34;token function&#34;&gt;add&lt;/span&gt; &lt;span class=&#34;token builtin class-name&#34;&gt;.&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;10&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token comment&#34;&gt;# 提交&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;11&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token function&#34;&gt;git&lt;/span&gt; commit -m &lt;span class=&#34;token string&#34;&gt;&#34;添加文件&#34;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;12&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;13&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token comment&#34;&gt;# 提交到 github&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;14&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token function&#34;&gt;git&lt;/span&gt; remote &lt;span class=&#34;token function&#34;&gt;add&lt;/span&gt; origin git@github.com:github_user_name/reporsity.git&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;15&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token function&#34;&gt;git&lt;/span&gt; push -u origin master&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;16&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;17&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token comment&#34;&gt;# 查看当前远程库&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;18&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token function&#34;&gt;git&lt;/span&gt; remote&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;19&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token function&#34;&gt;git&lt;/span&gt; remote -v 查看每个别名的实际地址&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;20&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;21&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token comment&#34;&gt;# 从远程仓库下载新分支与数据&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;22&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token function&#34;&gt;git&lt;/span&gt; fetch &lt;span class=&#34;token comment&#34;&gt;# 该命令执行完后需要执行 git merge 远程分支到你所在的分支&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;23&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token comment&#34;&gt;# 从远端仓库提取数据并尝试合并到当前分支&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;24&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token function&#34;&gt;git&lt;/span&gt; merge&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;25&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token comment&#34;&gt;# 当你想要提取更新的数据的时候&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;26&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token function&#34;&gt;git&lt;/span&gt; fetch &lt;span class=&#34;token punctuation&#34;&gt;[&lt;/span&gt;alias&lt;span class=&#34;token punctuation&#34;&gt;]&lt;/span&gt; &lt;span class=&#34;token comment&#34;&gt;# 告诉 Git 去获取它没有的数据&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;27&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token function&#34;&gt;git&lt;/span&gt; merge &lt;span class=&#34;token punctuation&#34;&gt;[&lt;/span&gt;alias&lt;span class=&#34;token punctuation&#34;&gt;]&lt;/span&gt;/&lt;span class=&#34;token punctuation&#34;&gt;[&lt;/span&gt;branch&lt;span class=&#34;token punctuation&#34;&gt;]&lt;/span&gt; &lt;span class=&#34;token comment&#34;&gt;#将远程仓库的任何更新合并到你的当前分支&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;28&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;29&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token comment&#34;&gt;# alias 为远程仓库的别名&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;30&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;31&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token comment&#34;&gt;# 将新分支和数据推送到你的远程仓库&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;32&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token function&#34;&gt;git&lt;/span&gt; push &lt;span class=&#34;token punctuation&#34;&gt;[&lt;/span&gt;alias&lt;span class=&#34;token punctuation&#34;&gt;]&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;[&lt;/span&gt;branch&lt;span class=&#34;token punctuation&#34;&gt;]&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;33&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;34&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token comment&#34;&gt;# 删除远程仓库&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;35&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token function&#34;&gt;git&lt;/span&gt; remote &lt;span class=&#34;token function&#34;&gt;rm&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;[&lt;/span&gt;alias&lt;span class=&#34;token punctuation&#34;&gt;]&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;36&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;37&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token comment&#34;&gt;# 添加仓库&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;38&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token function&#34;&gt;git&lt;/span&gt; remote &lt;span class=&#34;token function&#34;&gt;add&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;[&lt;/span&gt;alias&lt;span class=&#34;token punctuation&#34;&gt;]&lt;/span&gt; git@github.com:user_name/repo.git&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;h2 id=&#34;github高级用法&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#github高级用法&#34;&gt;#&lt;/a&gt; Github 高级用法&lt;/h2&gt;
&lt;h3 id=&#34;搜索技巧&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#搜索技巧&#34;&gt;#&lt;/a&gt; 搜索技巧&lt;/h3&gt;
&lt;p&gt;【s】--&amp;gt; 聚焦搜索 --&amp;gt;【enter】--&amp;gt; 进入搜索界面 --&amp;gt; 点击 &lt;code&gt;advanced search&lt;/code&gt; --&amp;gt; 进入高级搜索表单&lt;/p&gt;
&lt;h3 id=&#34;查找仓库中的文件&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#查找仓库中的文件&#34;&gt;#&lt;/a&gt; 查找仓库中的文件&lt;/h3&gt;
&lt;p&gt;【t】--&amp;gt; 查找文件&lt;/p&gt;
&lt;p&gt;【l】--&amp;gt; 跳转到某一行&lt;/p&gt;
&lt;p&gt;【b】--&amp;gt; 查看文件修改记录&lt;/p&gt;
&lt;p&gt;【C-v】--&amp;gt; 打开控制面板&lt;/p&gt;
&lt;p&gt;在仓库详情页按下【。】--&amp;gt; 打开一个网页版的 vscode 来查看项目&lt;/p&gt;
&lt;p&gt;&lt;span class=&#34;exturl&#34; data-url=&#34;&#34;&gt;在项目的链接中的 github.com 前加一个 gitpod.io/#/ 来打开项目：此时会根据项目的类型自用添加环境依赖&lt;/span&gt;&lt;/p&gt;
&lt;script type=&#34;text&amp;#x2F;javascript&#34; src=&#34;https://cdn.jsdelivr.net/npm/kity@2.0.4/dist/kity.min.js&#34;&gt;&lt;/script&gt;&lt;script type=&#34;text&amp;#x2F;javascript&#34; src=&#34;https://cdn.jsdelivr.net/npm/kityminder-core@1.4.50/dist/kityminder.core.min.js&#34;&gt;&lt;/script&gt;&lt;script defer=&#34;true&#34; type=&#34;text&amp;#x2F;javascript&#34; src=&#34;https://cdn.jsdelivr.net/npm/hexo-simple-mindmap@0.7.0/dist/mindmap.min.js&#34;&gt;&lt;/script&gt;&lt;link rel=&#34;stylesheet&#34; type=&#34;text&amp;#x2F;css&#34; href=&#34;https://cdn.jsdelivr.net/npm/hexo-simple-mindmap@0.7.0/dist/mindmap.min.css&#34;&gt;

 &lt;h1 id=&#34;调试core文件&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#调试core文件&#34;&gt;#&lt;/a&gt; 调试 core 文件&lt;/h1&gt;
&lt;p&gt;使用 &lt;code&gt;ulimit -a&lt;/code&gt;  查看当前系统受限文件&lt;br /&gt;
使用 &lt;code&gt;ulimit -c unlimited&lt;/code&gt;  对 core 文件解除限制&lt;br /&gt;
 &lt;code&gt;gdb 二进制文件 core&lt;/code&gt;&lt;/p&gt;
&lt;p&gt;指定一个进程来调试一个程序， &lt;code&gt;gdb program pid&lt;/code&gt;   &lt;code&gt;gdb -p pid&lt;/code&gt; &lt;br /&gt;
gdb 常用命令&lt;br /&gt;
 r run&lt;br /&gt;
l list&lt;br /&gt;
b break&lt;br /&gt;
bt  查看栈&lt;br /&gt;
 c continue&lt;br /&gt;
n next&lt;br /&gt;
e edit [file:]function&lt;br /&gt;
s step 跳进或跳出函数&lt;br /&gt;
 h help&lt;br /&gt;
q quit&lt;/p&gt;
&lt;h1 id=&#34;gdb多线程调试&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#gdb多线程调试&#34;&gt;#&lt;/a&gt; gdb 多线程调试&lt;/h1&gt;
&lt;h2 id=&#34;调试常用命令&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#调试常用命令&#34;&gt;#&lt;/a&gt; 调试常用命令&lt;/h2&gt;
&lt;ol&gt;
&lt;li&gt;&lt;code&gt;info thread&lt;/code&gt;  查看可切换调试的线程&lt;/li&gt;
&lt;li&gt;&lt;code&gt;thread tid&lt;/code&gt;  切换线程&lt;/li&gt;
&lt;li&gt;&lt;code&gt;set scheduler -locking on&lt;/code&gt;  只运行当前线程&lt;/li&gt;
&lt;li&gt;&lt;code&gt;set scheduler -locking off&lt;/code&gt;  运行全部线程&lt;/li&gt;
&lt;li&gt;&lt;code&gt;thread apply tid gdb_cmd&lt;/code&gt;  指定线程执行 gdb 执行&lt;/li&gt;
&lt;li&gt;&lt;code&gt;thread apply all gdb_cmd&lt;/code&gt;  全部的线程执行 gdb 指令&lt;/li&gt;
&lt;/ol&gt;
&lt;p&gt;测试用例 thread_test.c&lt;/p&gt;
&lt;figure class=&#34;highlight c&#34;&gt;&lt;figcaption data-lang=&#34;c&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token macro property&#34;&gt;&lt;span class=&#34;token directive-hash&#34;&gt;#&lt;/span&gt;&lt;span class=&#34;token directive keyword&#34;&gt;include&lt;/span&gt; &lt;span class=&#34;token string&#34;&gt;&amp;lt;pthread.h&gt;&lt;/span&gt;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;2&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token macro property&#34;&gt;&lt;span class=&#34;token directive-hash&#34;&gt;#&lt;/span&gt;&lt;span class=&#34;token directive keyword&#34;&gt;include&lt;/span&gt; &lt;span class=&#34;token string&#34;&gt;&amp;lt;stdio.h&gt;&lt;/span&gt;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;3&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token macro property&#34;&gt;&lt;span class=&#34;token directive-hash&#34;&gt;#&lt;/span&gt;&lt;span class=&#34;token directive keyword&#34;&gt;include&lt;/span&gt; &lt;span class=&#34;token string&#34;&gt;&amp;lt;stdlib.h&gt;&lt;/span&gt;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;4&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token macro property&#34;&gt;&lt;span class=&#34;token directive-hash&#34;&gt;#&lt;/span&gt;&lt;span class=&#34;token directive keyword&#34;&gt;include&lt;/span&gt; &lt;span class=&#34;token string&#34;&gt;&amp;lt;unistd.h&gt;&lt;/span&gt;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;5&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;int&lt;/span&gt; x&lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt;&lt;span class=&#34;token number&#34;&gt;0&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;y&lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt;&lt;span class=&#34;token number&#34;&gt;0&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;6&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token class-name&#34;&gt;pthread_t&lt;/span&gt; th1&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;th2&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;7&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;8&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token comment&#34;&gt;// 第一个线程&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;9&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;void&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;*&lt;/span&gt; &lt;span class=&#34;token function&#34;&gt;th1_do&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token keyword&#34;&gt;void&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;*&lt;/span&gt; arg&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;10&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;11&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;  &lt;span class=&#34;token keyword&#34;&gt;for&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;x&lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt;&lt;span class=&#34;token number&#34;&gt;0&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;x&lt;span class=&#34;token operator&#34;&gt;&amp;lt;&lt;/span&gt;&lt;span class=&#34;token number&#34;&gt;100&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;x&lt;span class=&#34;token o